CONTENT_OS_RLS_TABLES = [
    "kb_entries",
    "content_briefs",
    "assets",
    "media_assets",
    "publish_queue",
    "raw_metrics",
    "feedback",
    "outcomes",
    "learning_weights",
]


async def supabase_table_probe(table: str):
    if not supabase_rest.configured():
        return {
            "table": f"public.{table}",
            "status": "not_configured",
            "row_count": None,
            "detail": "Supabase REST is not configured on the server.",
        }
    try:
        row_count = await supabase_rest.count_strict(table)
        return {
            "table": f"public.{table}",
            "status": "accessible",
            "row_count": row_count,
            "detail": "Server-side Supabase REST read succeeded.",
        }
    except httpx.HTTPStatusError as exc:
        return {
            "table": f"public.{table}",
            "status": "blocked",
            "row_count": None,
            "http_status": exc.response.status_code,
            "detail": "Server-side Supabase REST read was rejected.",
        }
    except Exception as exc:
        return {
            "table": f"public.{table}",
            "status": "error",
            "row_count": None,
            "error_type": exc.__class__.__name__,
            "detail": "Server-side Supabase REST read failed.",
        }


async def data_connection_status_payload(sample_tables: list[str] | None = None):
    postgres_connected = bool(await fetch_row("select 1 as ok"))
    tables = sample_tables or CONTENT_OS_RLS_TABLES
    probes = [await supabase_table_probe(table) for table in tables]
    accessible_count = sum(1 for probe in probes if probe.get("status") == "accessible")
    supabase_configured = supabase_rest.configured()
    rest_accessible = bool(supabase_configured and accessible_count == len(probes) and probes)
    data_backend = "postgres" if postgres_connected else "supabase_rest" if rest_accessible else "not_connected"
    return {
        "mode": "server_side_data_connection",
        "postgres_direct": "configured" if postgres_connected else "not_connected",
        "supabase_rest": "accessible" if rest_accessible else "configured" if supabase_configured else "not_connected",
        "data_backend": data_backend,
        "rest_accessible_tables": accessible_count,
        "rest_checked_tables": len(probes),
        "summary": (
            "Direct Postgres is configured."
            if postgres_connected
            else f"Direct Postgres is not configured; Supabase REST can access {accessible_count}/{len(probes)} checked table(s)."
        ),
        "tables": probes,
        "safety": [
            "This diagnostic never returns database passwords, API keys, or service-role tokens.",
            "Browser clients still use only the protected Fly API.",
            "Strict RLS hardening still requires SUPABASE_SERVICE_ROLE_KEY and a recent service-role smoke test.",
        ],
    }


def rls_advisor_summary(has_service_role: bool, smoke_recent: bool = False):
    status = "ready_to_harden" if has_service_role and smoke_recent else "blocked_until_service_role_smoke"
    return {
        "status": status,
        "advisor_source": "Supabase security advisor checked via connected Supabase project tooling.",
        "project_ref": "ddzqgttrwfwssxnayfsd",
        "warning": "rls_policy_always_true",
        "warning_count": len(CONTENT_OS_RLS_TABLES),
        "affected_tables": [f"public.{table}" for table in CONTENT_OS_RLS_TABLES],
        "current_policy": "drec_api_rest_access allows anon/authenticated ALL with USING true and WITH CHECK true.",
        "target_policy": "drec_service_role_access only, with anon/authenticated direct table access revoked.",
        "migration": "supabase/migrations/20260617040906_strict_server_only_rls.sql",
        "blocker": "" if has_service_role and smoke_recent else "Do not apply strict RLS until SUPABASE_SERVICE_ROLE_KEY is installed on Fly and service-role smoke is recent.",
    }


def supabase_project_ref():
    if not settings.supabase_url:
        return None
    match = re.search(r"https://([a-z0-9-]+)\.supabase\.co", settings.supabase_url.strip(), re.IGNORECASE)
    return match.group(1) if match else None


def supabase_dashboard_api_settings_url():
    project_ref = supabase_project_ref()
    return f"https://supabase.com/dashboard/project/{project_ref}/settings/api" if project_ref else None


def security_status_payload():
    has_service_role = bool(settings.supabase_service_role_key)
    has_supabase_rest = bool(settings.supabase_url and supabase_rest.api_key())
    fallback_key_mode = bool(settings.supabase_api_key and not settings.supabase_service_role_key)
    rls_ready = has_service_role and has_supabase_rest
    rls_advisor = rls_advisor_summary(has_service_role, False)
    return {
        "overall_status": "ready_for_rls_hardening" if rls_ready else "needs_service_role_key",
        "supabase_rest": "configured" if has_supabase_rest else "missing",
        "service_role_key": "configured" if has_service_role else "missing",
        "fallback_key_mode": fallback_key_mode,
        "direct_browser_supabase": "disabled_by_design",
        "supabase_project_ref": supabase_project_ref(),
        "supabase_api_settings_url": supabase_dashboard_api_settings_url(),
        "rls_hardening_ready": rls_ready,
        "rls_advisor": rls_advisor,
        "checks": [
            {
                "label": "Fly API uses Supabase REST",
                "status": "ready" if has_supabase_rest else "missing",
            },
            {
                "label": "Service role key installed on Fly",
                "status": "ready" if has_service_role else "missing",
            },
            {
                "label": "Browser talks only to protected API",
                "status": "ready",
            },
            {
                "label": "Supabase advisor RLS warnings are tracked",
                "status": "ready" if rls_advisor.get("warning_count") else "missing",
                "detail": f"{rls_advisor.get('warning_count')} permissive Content OS policy warning(s).",
            },
        ],
        "next_step": (
            "Apply strict Supabase RLS policies after live smoke passes with SUPABASE_SERVICE_ROLE_KEY."
            if rls_ready
            else "Add SUPABASE_SERVICE_ROLE_KEY to Fly before tightening Supabase RLS policies."
        ),
    }


async def strict_security_status_payload():
    security = security_status_payload()
    data_connection = await data_connection_status_payload()
    smoke = await latest_service_role_smoke()
    has_service_role = security.get("service_role_key") == "configured"
    has_supabase_rest = security.get("supabase_rest") == "configured"
    data_backend_ready = data_connection.get("data_backend") in {"postgres", "supabase_rest"}
    smoke_recent = smoke.get("status") == "recent"
    strict_ready = bool(has_service_role and has_supabase_rest and smoke_recent)
    if strict_ready:
        overall_status = "ready_for_rls_hardening"
        next_step = "Run live smoke, then apply the RLS hardening plan."
    elif not has_service_role:
        overall_status = "needs_service_role_key"
        next_step = "Add SUPABASE_SERVICE_ROLE_KEY to Fly, then run the service-role smoke test."
    elif not has_supabase_rest:
        overall_status = "supabase_rest_missing"
        next_step = "Confirm SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY are set on Fly."
    else:
        overall_status = "needs_service_role_smoke"
        next_step = "Run /security/service-role-smoke-test with an admin token before strict RLS hardening."
    checks = list(security.get("checks") or [])
    checks.append(
        {
            "label": "Server data backend can read Content OS tables",
            "status": "ready" if data_backend_ready else "blocked",
            "detail": data_connection.get("summary"),
        }
    )
    checks.append(
        {
            "label": "Recent service-role smoke test passed",
            "status": "ready" if smoke_recent else smoke.get("status", "missing"),
        }
    )
    rls_advisor = rls_advisor_summary(has_service_role, smoke_recent)
    return {
        **security,
        "overall_status": overall_status,
        "data_connection": data_connection,
        "data_backend": data_connection.get("data_backend"),
        "rls_hardening_ready": strict_ready,
        "rls_advisor": rls_advisor,
        "service_role_smoke": smoke,
        "service_role_smoke_recent_minutes": SERVICE_ROLE_SMOKE_RECENT_MINUTES,
        "checks": checks,
        "next_step": next_step,
    }


@app.get("/security/status")
async def security_status(_: None = Depends(require_access_token)):
    return await strict_security_status_payload()


@app.get("/security/data-connection")
async def security_data_connection(_: None = Depends(require_access_token)):
    return await data_connection_status_payload()


@app.post("/security/service-role-smoke-test")
async def security_service_role_smoke_test(session: dict = Depends(require_admin_access)):
    security = await strict_security_status_payload()
    if not settings.supabase_service_role_key:
        return {
            "mode": "service_role_smoke_test",
            "status": "missing_service_role_key",
            "passed": False,
            "security": security,
            "message": "SUPABASE_SERVICE_ROLE_KEY is not installed on Fly yet.",
            "next_step": "Install the service-role key with the Service Role Install Pack, then rerun this smoke test.",
            "safety": [
                "This test never displays or returns secret values.",
                "No RLS policy should be tightened until this smoke test passes.",
            ],
        }
    if not supabase_rest.configured():
        return {
            "mode": "service_role_smoke_test",
            "status": "supabase_rest_missing",
            "passed": False,
            "security": security,
            "message": "Supabase REST is not configured.",
            "next_step": "Confirm SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY are set on Fly.",
            "safety": [
                "This test never displays or returns secret values.",
                "No RLS policy should be tightened until this smoke test passes.",
            ],
        }
    marker = f"service-role-smoke-{uuid4()}"
    payload = {
        "module": "security",
        "ref_type": "service_role",
        "ref_id": marker,
        "action": "heartbeat",
        "before_text": json.dumps(
            {
                "kind": "service_role_smoke_test",
                "recorded_at": datetime.now(timezone.utc).isoformat(),
                "api_key_source": "supabase_service_role_key",
            },
            ensure_ascii=False,
        ),
        "after_text": None,
        "reason": "Server-side Supabase service-role smoke test succeeded.",
        "tags": ["service-role-smoke", "security", *audit_tags(session)],
    }
    try:
        inserted = await supabase_rest.insert("feedback", payload)
    except Exception as exc:
        return {
            "mode": "service_role_smoke_test",
            "status": "failed",
            "passed": False,
            "security": security,
            "message": "Server-side service-role REST write failed.",
            "error_type": exc.__class__.__name__,
            "next_step": "Confirm the service-role key belongs to this Supabase project and Fly has restarted after setting the secret.",
            "safety": [
                "This response does not expose the service-role key.",
                "Keep strict RLS changes paused until the smoke test passes.",
            ],
        }
    return {
        "mode": "service_role_smoke_test",
        "status": "passed",
        "passed": True,
        "security": await strict_security_status_payload(),
        "feedback_id": (inserted or {}).get("id"),
        "ref_id": marker,
        "message": "Server-side Supabase service-role REST write succeeded.",
        "next_step": "Run live smoke, then use the RLS hardening plan before applying strict policies.",
        "safety": [
            "This test writes one audit heartbeat row to feedback as proof.",
            "It never displays, stores in the browser, or returns the service-role key.",
            "Real Meta jobs still remain locked behind Meta readiness and live switches.",
        ],
    }


