async def first_publish_readiness_payload():
    checklist = await test_run_checklist_payload()
    assets = await fetch_asset_list(200)
    queue = await fetch_publish_queue_items(200)
    meta = await meta_readiness(None)
    schedule_audit = await schedule_audit_payload()
    ready_assets = assets_ready_for_queue(assets)
    next_asset = next((item for item in assets if item not in ready_assets), assets[0] if assets else None)
    media_gate_asset = ready_assets[0] if ready_assets else next_asset
    media_gate = first_publish_media_gate(media_gate_asset)
    publish_ready_assets = [item for item in ready_assets if first_publish_media_ready(item)]
    review_approved_queue = [
        item
        for item in queue
        if item.get("status") == "draft"
        and item.get("compliance_status") == "clear"
        and (item.get("latest_feedback") or {}).get("action") == "approve"
    ]
    review_needed_queue = [
        item
        for item in queue
        if item.get("status") == "draft"
        and item.get("compliance_status") == "clear"
        and (item.get("latest_feedback") or {}).get("action") != "approve"
    ]
    scheduled_queue = [
        item
        for item in queue
        if item.get("status") == "scheduled" and item.get("planned_slot") and item.get("compliance_status") == "clear"
    ]
    fb_item = await next_facebook_publish_item()
    ig_item = await next_instagram_publish_item()
    fb_blockers = facebook_dispatch_blockers(fb_item, meta)
    ig_blockers = instagram_dispatch_blockers(ig_item, meta)
    stages = [
        first_publish_stage(
            "asset_review",
            "Asset approved and safety clear",
            "done" if ready_assets else "open" if assets else "locked",
            f"{len(ready_assets)} ready asset(s)." if ready_assets else f"{len(assets)} asset(s) exist; approve one with explicit safety clear." if assets else "Generate and save one asset first.",
            "Open Assets",
            "assets",
            {"asset_count": len(assets), "ready_assets": len(ready_assets), "next_asset_id": next_asset.get("id") if next_asset else None},
        ),
        first_publish_stage(
            "media_ready",
            "Media/design ready when required",
            "done" if queue or publish_ready_assets or (ready_assets and not media_gate.get("required")) else "open" if ready_assets else "locked",
            media_gate.get("detail") if ready_assets or next_asset else "Generate and save one asset first.",
            "Attach Media",
            "assets",
            media_gate,
        ),
        first_publish_stage(
            "queue",
            "Queue item created",
            "done" if queue else "open" if publish_ready_assets else "locked",
            f"{len(queue)} queue item(s) exist." if queue else "Queue one approved clear asset with required media/design ready.",
            "Queue Ready Asset",
            "assets",
            {"queue_total": len(queue)},
        ),
        first_publish_stage(
            "review_queue",
            "Queue item review-approved",
            "done" if review_approved_queue or scheduled_queue else "open" if queue else "locked",
            f"{len(review_approved_queue)} review-approved draft item(s)." if review_approved_queue else "Approve one queue item before scheduling.",
            "Open Review Queue",
            "review",
            {"review_approved_queue": len(review_approved_queue)},
        ),
        first_publish_stage(
            "schedule",
            "Queue item scheduled",
            "done" if scheduled_queue else "open" if review_approved_queue else "locked",
            f"{len(scheduled_queue)} scheduled item(s)." if scheduled_queue else "Suggest or import one planned slot after queue review approval.",
            "Open Scheduler",
            "scheduler",
            {"scheduled_queue": len(scheduled_queue), "schedule_audit": schedule_audit.get("overall_status")},
        ),
        first_publish_stage(
            "meta_dry_run",
            "Meta worker dry run",
            "done" if (fb_item and not fb_blockers) or (ig_item and not ig_blockers) else "open" if scheduled_queue else "locked",
            "A due scheduled item is ready for Meta dry run." if (fb_item and not fb_blockers) or (ig_item and not ig_blockers) else "Dry run is waiting for a scheduled compliance-clear item.",
            "Dry Run Meta Publishing",
            "scheduler",
            {"facebook_blockers": fb_blockers, "instagram_blockers": ig_blockers},
        ),
    ]
    next_stage = next((stage for stage in stages if stage["status"] in {"open", "locked"}), stages[-1])
    after_approval_plan = [
        {
            "key": "confirm_human_approval",
            "status": "open" if not ready_assets else "done",
            "label": "Confirm doctor approval phrase",
            "detail": "Require Decision: approve and Safety: clear before approving the first-publish asset.",
            "screen": "assets",
            "action": "Approve Current First Publish",
        },
        {
            "key": "attach_generated_media",
            "status": "done" if media_gate.get("ready") else "open" if ready_assets else "locked",
            "label": "Attach approved generated media",
            "detail": media_gate.get("detail") or "Attach approved public media/design URLs before queueing visual content.",
            "screen": "assets",
            "action": "Attach Generated Media",
        },
        {
            "key": "queue_first_asset",
            "status": "done" if queue else "open" if publish_ready_assets else "locked",
            "label": "Move asset into review queue",
            "detail": "Use Advance Safe Step or Queue Ready Assets after approval and media readiness.",
            "screen": "assets",
            "action": "Advance Safe Step",
        },
        {
            "key": "approve_queue_item",
            "status": "done" if review_approved_queue or scheduled_queue else "open" if review_needed_queue else "locked",
            "label": "Approve queue item",
            "detail": "Require reviewer_action=approve before scheduling.",
            "screen": "review",
            "action": "Approve Current Queue Item",
        },
        {
            "key": "schedule_and_handoff",
            "status": "done" if scheduled_queue else "open" if review_approved_queue else "locked",
            "label": "Schedule and build handoff",
            "detail": "Schedule only review-approved, compliance-clear items; then build the manual publishing handoff.",
            "screen": "scheduler",
            "action": "Schedule Approved",
        },
        {
            "key": "measure_and_learn",
            "status": "open" if scheduled_queue else "locked",
            "label": "Record metrics and roll up learning",
            "detail": "After manual publishing, record the Meta post ID and first metrics, then roll them into learning.",
            "screen": "outcomes",
            "action": "Open Performance",
        },
    ]
    return {
        "overall_status": "ready_for_meta_dry_run" if next_stage["key"] == "meta_dry_run" and next_stage["status"] == "open" else "building_first_publish_item",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "next_step": next_stage,
        "manual_cycle": {
            "done_count": checklist.get("done_count"),
            "total_required": checklist.get("total_required"),
            "checklist_next_step": checklist.get("next_step"),
        },
        "stages": stages,
        "after_approval_plan": after_approval_plan,
        "candidates": {
            "next_asset": next_asset,
            "ready_asset": publish_ready_assets[0] if publish_ready_assets else None,
            "approved_clear_asset": ready_assets[0] if ready_assets else None,
            "review_needed_queue": review_needed_queue[0] if review_needed_queue else None,
            "review_approved_queue": review_approved_queue[0] if review_approved_queue else None,
            "scheduled_queue": scheduled_queue[0] if scheduled_queue else None,
            "facebook_dispatch_item": fb_item,
            "instagram_dispatch_item": ig_item,
        },
        "action_pack": {
            "next_asset_decision_csv": asset_review_decision_csv_text(next_asset) if next_asset else "",
            "next_queue_decision_csv": review_queue_decision_csv_text(review_needed_queue[0]) if review_needed_queue else "",
            "next_asset_review_pack": "/operations/asset-review-session.md",
            "asset_decision_import": "/operations/import-asset-review-decisions",
            "queue_decision_import": "/operations/import-review-queue-decisions",
            "media_gate": media_gate,
            "production_handoff": "/operations/production-handoff-bridge.zh.md",
            "production_reply_import": "/operations/import-production-replies",
            "instructions": [
                "Copy or fill the one-row CSV template for the next asset.",
                "A human reviewer must fill reviewer_safety_decision and reviewer_review_decision.",
                "Use clear + approve only when the safety checklist is truly passed.",
                "If media/design is required, attach approved media URLs before queueing.",
                "Importing the worksheet does not queue, schedule, or publish by itself.",
            ],
        },
        "meta": {
            "overall_status": meta.get("overall_status"),
            "permission_proof_status": meta.get("permission_proof_status"),
            "channels": meta.get("channels"),
            "facebook_blockers": fb_blockers,
            "instagram_blockers": ig_blockers,
        },
        "links": {
            "asset_review": "/operations/asset-review-session.md",
            "asset_decisions": "/operations/asset-review-decisions.csv",
            "review_queue": "/operations/review-queue.csv",
            "review_queue_decisions": "/operations/review-queue-decisions.csv",
            "pre_schedule_gate": "/operations/pre-schedule-gate.md",
            "schedule_audit": "/publish-queue/schedule-audit.md",
            "meta_preflight": "/meta/preflight-audit.md",
            "publishing_handoff": "/publishing-handoff",
        },
        "safety": [
            "This readiness pack is read-only.",
            "Do not approve assets unless the reviewer explicitly marks safety clear and approved.",
            "Do not schedule queue items before review approval and pre-schedule checks.",
            "Keep live Meta switches off until dry runs and setup gates are green.",
        ],
    }


@app.post("/operations/first-publish-advance")
async def operations_first_publish_advance(
    request: Request,
    dry_run: bool = True,
    session: dict = Depends(require_schedule_access),
):
    payload = await first_publish_readiness_payload()
    candidates = payload.get("candidates") or {}
    next_step = payload.get("next_step") or {}
    result = {
        "dry_run": dry_run,
        "before_status": payload.get("overall_status"),
        "next_step": next_step,
        "advanced": False,
        "action": "blocked",
        "message": next_step.get("detail") or "First publish path is not ready to advance.",
        "result": None,
        "safety": [
            "This endpoint never approves assets or queue items.",
            "It only attaches generated media to already approved clear assets, queues already approved clear assets, schedules review-approved queue items, or runs Meta dry-run checks.",
            "Live Meta publishing remains locked behind existing Meta enable flags.",
        ],
    }
    if next_step.get("key") == "asset_review":
        result["action"] = "needs_asset_review"
        result["message"] = "Human asset safety and approval decisions are required before auto-advance can continue."
        result["action_pack"] = payload.get("action_pack")
        return result
    if next_step.get("key") == "media_ready":
        asset = candidates.get("approved_clear_asset")
        if not asset:
            result["action"] = "needs_asset_review"
            result["message"] = "Human asset safety and approval decisions are required before media can be attached."
            result["action_pack"] = payload.get("action_pack")
            return result
        if not first_publish_media_required(asset):
            result["action"] = "no_media_required"
            result["message"] = "This first-publish format does not require generated media URLs."
            return result
        media_urls = first_publish_generated_media_urls(request, asset)
        result["action"] = "attach_generated_media"
        result["message"] = f"Generated media URLs can be attached to approved asset {asset.get('id')}."
        if dry_run:
            result["planned"] = {"asset_id": asset.get("id"), "media_urls": media_urls}
            return result
        attached = await update_asset_media(
            str(asset.get("id")),
            AssetMediaIn(
                media_urls=media_urls,
                reason="Generated first-publish PNG media URLs during safe first-publish advance.",
                visual_qa_status="pending",
                rights_note="Generated by DREC Content OS from approved asset copy.",
                sync_draft_queue=True,
            ),
            session,
        )
        result.update({"advanced": True, "result": attached, "message": "Attached generated media URLs to the first approved clear asset."})
        result["after"] = await first_publish_readiness_payload()
        return result
    if next_step.get("key") == "queue":
        asset = candidates.get("ready_asset")
        if not asset:
            result["action"] = "needs_ready_asset"
            result["message"] = "No approved compliance-clear asset is available to queue."
            return result
        result["action"] = "queue_ready_asset"
        result["message"] = f"Ready asset {asset.get('id')} can be queued."
        if dry_run:
            result["planned"] = {"asset_id": asset.get("id"), "channel": asset.get("channel"), "format": asset.get("format")}
            return result
        queued = await queue_asset(str(asset.get("id")))
        result.update({"advanced": True, "result": queued, "message": "Queued the first approved clear asset."})
        result["after"] = await first_publish_readiness_payload()
        return result
    if next_step.get("key") == "review_queue":
        result["action"] = "needs_queue_review"
        result["message"] = "Human queue review approval is required before scheduling."
        result["action_pack"] = payload.get("action_pack")
        return result
    if next_step.get("key") == "schedule":
        item = candidates.get("review_approved_queue")
        if not item:
            result["action"] = "needs_review_approved_queue"
            result["message"] = "No review-approved queue item is available to schedule."
            return result
        result["action"] = "schedule_review_approved"
        result["message"] = f"Review-approved queue item {item.get('id')} can be scheduled."
        if dry_run:
            result["planned"] = {"queue_id": item.get("id"), "channel": item.get("channel"), "format": item.get("format")}
            return result
        scheduled = await schedule_publish_queue_next_slot(str(item.get("id")))
        result.update({"advanced": True, "result": scheduled, "message": "Scheduled the first review-approved queue item."})
        result["after"] = await first_publish_readiness_payload()
        return result
    if next_step.get("key") == "meta_dry_run":
        result["action"] = "meta_dry_run"
        result["message"] = "Running Meta publishing dry run for due scheduled items."
        dry_run_result = await meta_publishing_job(channel="all", dry_run=True)
        result.update({"advanced": bool(dry_run_result.get("ready_count")), "result": dry_run_result})
        return result
    result["action"] = "complete_or_unknown"
    result["message"] = "No automatic first publish action is available."
    return result


@app.post("/operations/first-publish-safe-advance-loop")
async def operations_first_publish_safe_advance_loop(
    request: Request,
    dry_run: bool = True,
    max_steps: int = 6,
    session: dict = Depends(require_schedule_access),
):
    step_limit = max(1, min(int(max_steps or 1), 10))
    actions = []
    stop_reason = "step_limit_reached"
    for _ in range(step_limit):
        step = await operations_first_publish_advance(request, dry_run=dry_run, session=session)
        actions.append(
            {
                "action": step.get("action"),
                "advanced": bool(step.get("advanced")),
                "message": step.get("message"),
                "planned": step.get("planned"),
                "next_step": step.get("next_step"),
            }
        )
        if dry_run:
            stop_reason = "dry_run_preview_only"
            break
        if step.get("action") in {"needs_asset_review", "needs_queue_review", "needs_review_approved_queue"}:
            stop_reason = step.get("action")
            break
        if step.get("action") == "meta_dry_run":
            stop_reason = "meta_dry_run_completed"
            break
        if not step.get("advanced"):
            stop_reason = step.get("action") or "manual_gate_or_no_action"
            break
    after = await first_publish_readiness_payload()
    return {
        "mode": "first_publish_safe_advance_loop",
        "dry_run": dry_run,
        "max_steps": step_limit,
        "executed_steps": len(actions),
        "advanced_count": sum(1 for item in actions if item.get("advanced")),
        "stop_reason": stop_reason,
        "actions": actions,
        "after_next_step": after.get("next_step"),
        "after_overall_status": after.get("overall_status"),
        "message": (
            f"Safe advance loop ran {len(actions)} step(s); {sum(1 for item in actions if item.get('advanced'))} changed state; stopped at {stop_reason}."
        ),
        "safety": [
            "This loop never approves an asset or queue item.",
            "It never publishes live Meta posts.",
            "It only repeats existing safe mechanical steps after required human gates are already satisfied.",
            "It stops at doctor/human review, queue review, Meta dry-run, no-op, or the step limit.",
        ],
    }


@app.post("/operations/first-cycle-dry-run-rehearsal")
async def operations_first_cycle_dry_run_rehearsal(
    request: Request,
    _: None = Depends(require_access_token),
):
    readiness = await first_publish_readiness_payload()
    first_advance = await operations_first_publish_advance(request, dry_run=True, session={})
    monthly_advance = await operations_monthly_carousel_safe_advance(dry_run=True, max_actions=10, _=None)
    pre_schedule = await pre_schedule_gate_payload()
    meta_dry_run = await meta_publishing_job(channel="all", dry_run=True)
    completion = await project_completion_audit_payload()
    next_step = readiness.get("next_step") or {}
    first_action = first_advance.get("action")
    monthly_actions = monthly_advance.get("actions") or []
    rehearsal_steps = [
        {
            "key": "doctor_approval",
            "status": "blocked" if next_step.get("key") == "asset_review" else "ready",
            "label": "Doctor or human approval",
            "detail": next_step.get("detail") if next_step.get("key") == "asset_review" else "Approval gate is not the current blocker.",
        },
        {
            "key": "media_ready",
            "status": "would_run" if first_action == "attach_generated_media" else "waiting",
            "label": "Attach approved/generated media",
            "detail": first_advance.get("message") if first_action == "attach_generated_media" else "Media attachment waits for approval or is already satisfied.",
        },
        {
            "key": "queue",
            "status": "would_run" if first_action == "queue_ready_asset" or monthly_advance.get("would_queue") else "waiting",
            "label": "Queue approved clear asset",
            "detail": first_advance.get("message") if first_action == "queue_ready_asset" else f"{monthly_advance.get('would_queue', 0)} monthly asset(s) would queue.",
        },
        {
            "key": "queue_review",
            "status": "blocked" if next_step.get("key") == "review_queue" else "waiting",
            "label": "Human queue review",
            "detail": "Queue review approval is still a human gate." if next_step.get("key") == "review_queue" else "No queue item is currently waiting at this gate.",
        },
        {
            "key": "schedule",
            "status": "would_run" if first_action == "schedule_review_approved" or monthly_advance.get("would_schedule") else "waiting",
            "label": "Schedule reviewed item",
            "detail": f"{pre_schedule.get('ready_to_schedule_count', 0)} item(s) pass pre-schedule gate.",
        },
        {
            "key": "meta_dry_run",
            "status": "would_run" if meta_dry_run.get("ready_count") else "waiting",
            "label": "Meta dry-run",
            "detail": f"{meta_dry_run.get('ready_count', 0)} due scheduled item(s) ready for dry-run.",
        },
    ]
    first_open = next((item for item in rehearsal_steps if item.get("status") in {"blocked", "would_run"}), rehearsal_steps[0])
    return {
        "mode": "first_cycle_dry_run_rehearsal",
        "dry_run": True,
        "overall_status": "blocked_by_human_gate" if first_open.get("status") == "blocked" else "ready_for_next_safe_action",
        "next_step": first_open,
        "rehearsal_steps": rehearsal_steps,
        "first_publish": {
            "overall_status": readiness.get("overall_status"),
            "next_step": next_step,
            "advance_action": first_action,
            "advance_message": first_advance.get("message"),
        },
        "monthly_safe_advance": {
            "action_count": monthly_advance.get("action_count"),
            "would_queue": monthly_advance.get("would_queue"),
            "would_schedule": monthly_advance.get("would_schedule"),
            "actions": monthly_actions[:10],
        },
        "pre_schedule_gate": {
            "ready_to_schedule_count": pre_schedule.get("ready_to_schedule_count"),
            "blocked_count": pre_schedule.get("blocked_count"),
        },
        "meta_dry_run": {
            "ready_count": meta_dry_run.get("ready_count"),
            "dry_run": meta_dry_run.get("dry_run"),
        },
        "completion": {
            "percent": ((completion.get("completion") or {}).get("percent")),
            "first_cycle_percent": ((completion.get("completion") or {}).get("first_cycle_percent")),
            "blockers": ((completion.get("completion") or {}).get("blockers") or [])[:6],
        },
        "safety": [
            "This rehearsal is dry-run only and does not approve, import, attach media, queue, schedule, publish, write Notion, or call Meta live publishing.",
            "It reuses the same gates as the live workflow, including human approval, queue review, pre-schedule checks, and Meta dry-run locks.",
            "Use it after each human decision import to see the next safe action.",
        ],
    }


@app.post("/operations/first-publish-attach-generated-media")
async def operations_first_publish_attach_generated_media(
    request: Request,
    dry_run: bool = True,
    session: dict = Depends(require_review_access),
):
    payload = await first_publish_readiness_payload()
    candidates = payload.get("candidates") or {}
    asset = candidates.get("approved_clear_asset") or candidates.get("ready_asset")
    if not asset:
        return {
            "dry_run": dry_run,
            "attached": False,
            "action": "needs_asset_review",
            "message": "A human-approved and safety-clear asset is required before generated media URLs can be attached.",
            "safety": [
                "This operation never approves an asset.",
                "Generated media URLs are available only after human approval and safety clear.",
                "Queueing, scheduling, and publishing remain separate gates.",
            ],
            "readiness": payload,
        }
    if not first_publish_asset_is_approved_clear(asset):
        return {
            "dry_run": dry_run,
            "attached": False,
            "action": "blocked_by_safety_gate",
            "asset_id": asset.get("id"),
            "message": "Generated media URLs are available only after human approval and safety clear.",
            "readiness": payload,
        }
    if not first_publish_media_required(asset):
        return {
            "dry_run": dry_run,
            "attached": False,
            "action": "no_media_required",
            "asset_id": asset.get("id"),
            "message": "This first-publish format does not require generated media URLs.",
            "readiness": payload,
        }
    media_urls = first_publish_generated_media_urls(request, asset)
    result = {
        "dry_run": dry_run,
        "attached": False,
        "action": "attach_generated_media",
        "asset_id": asset.get("id"),
        "media_count": len(media_urls),
        "media_urls": media_urls,
        "message": "Generated PNG media URLs are ready to attach after approval and safety clear.",
        "safety": [
            "This operation never approves, queues, schedules, or publishes content.",
            "Public PNG URLs return 404 until the asset is approved and safety clear.",
            "Visual QA remains pending after attachment.",
        ],
    }
    if dry_run:
        result["planned"] = {"media_urls": media_urls}
        return result
    attached = await update_asset_media(
        str(asset.get("id")),
        AssetMediaIn(
            media_urls=media_urls,
            reason="Generated first-publish PNG media URLs after human approval and safety clear.",
            visual_qa_status="pending",
            rights_note="Generated by DREC Content OS from approved asset copy.",
            sync_draft_queue=True,
        ),
        session,
    )
    result.update(
        {
            "attached": True,
            "result": attached,
            "message": "Generated PNG media URLs attached. Visual QA, queue review, scheduling, and publishing remain separate gates.",
            "after": await first_publish_readiness_payload(),
        }
    )
    return result


@app.post("/operations/first-publish-approve-current-asset")
async def operations_first_publish_approve_current_asset(
    dry_run: bool = True,
    session: dict = Depends(require_review_access),
):
    payload = await first_publish_readiness_payload()
    candidates = payload.get("candidates") or {}
    asset = candidates.get("next_asset")
    if not asset:
        return {
            "dry_run": dry_run,
            "approved": False,
            "action": "no_asset",
            "message": "No current first-publish asset is available for approval.",
            "readiness": payload,
        }
    if asset.get("review_status") == "approved" and asset.get("compliance_status") == "clear":
        return {
            "dry_run": dry_run,
            "approved": False,
            "action": "already_approved_clear",
            "asset_id": asset.get("id"),
            "message": "Current first-publish asset is already approved and safety clear.",
            "readiness": payload,
        }
    compliance = check_text(asset.get("caption") or "")
    result = {
        "dry_run": dry_run,
        "approved": False,
        "action": "approve_current_first_publish_asset",
        "asset_id": asset.get("id"),
        "compliance": compliance,
        "message": "Ready for explicit human approval if the reviewer confirms the image preview and caption are safe.",
        "safety": [
            "This operation requires review access and an explicit button click.",
            "It only approves the current first-publish asset.",
            "It refuses flagged medical copy.",
            "Queueing, scheduling, and publishing remain separate gates.",
        ],
    }
    if compliance.get("status") == "flagged":
        result.update(
            {
                "action": "blocked_by_compliance",
                "message": "Compliance check flagged this asset; revise or reject it before approval.",
            }
        )
        return result
    if dry_run:
        result["planned"] = {
            "asset_id": asset.get("id"),
            "compliance_status": "clear",
            "review_status": "approved",
        }
        return result
    await update_asset_compliance(
        str(asset.get("id")),
        AssetComplianceIn(
            compliance_status="clear",
            reason="Current first-publish asset safety-cleared by explicit reviewer action after system compliance check.",
        ),
        session,
    )
    approved = await update_asset_status(
        str(asset.get("id")),
        AssetStatusIn(
            review_status="approved",
            reason="Current first-publish asset approved by explicit reviewer action.",
        ),
        session,
    )
    result.update(
        {
            "approved": True,
            "result": approved,
            "message": "Current first-publish asset approved and safety clear. Media attachment, queueing, scheduling, and publishing remain separate gates.",
            "after": await first_publish_readiness_payload(),
        }
    )
    return result


@app.post("/operations/first-publish-approve-current-queue")
async def operations_first_publish_approve_current_queue(
    dry_run: bool = True,
    session: dict = Depends(require_review_access),
):
    payload = await first_publish_readiness_payload()
    candidates = payload.get("candidates") or {}
    item = candidates.get("review_needed_queue") or candidates.get("review_approved_queue")
    if not item:
        return {
            "dry_run": dry_run,
            "approved": False,
            "action": "no_queue_item",
            "message": "No current first-publish queue item is available for review approval.",
            "readiness": payload,
        }
    latest_feedback = item.get("latest_feedback") or {}
    if latest_feedback.get("action") == "approve":
        return {
            "dry_run": dry_run,
            "approved": False,
            "action": "already_review_approved",
            "queue_id": item.get("id"),
            "message": "Current first-publish queue item is already review-approved.",
            "readiness": payload,
        }
    compliance = check_text(item.get("caption") or "")
    media_count = len([url for url in item.get("media_urls") or [] if url])
    result = {
        "dry_run": dry_run,
        "approved": False,
        "action": "approve_current_first_publish_queue",
        "queue_id": item.get("id"),
        "asset_id": item.get("asset_id"),
        "compliance": compliance,
        "media_count": media_count,
        "message": "Ready for explicit queue review approval if the reviewer confirms caption, media, and timing fit.",
        "safety": [
            "This operation requires review access and an explicit button click.",
            "It only records approval feedback for the current first-publish queue item.",
            "It refuses flagged medical copy and queue items without required media.",
            "Scheduling and publishing remain separate gates.",
        ],
    }
    if item.get("status") != "draft":
        result.update(
            {
                "action": "blocked_by_status",
                "message": "Only draft queue items can receive review approval.",
            }
        )
        return result
    if item.get("compliance_status") != "clear" or compliance.get("status") == "flagged":
        result.update(
            {
                "action": "blocked_by_compliance",
                "message": "Compliance check blocked this queue item; revise or reject it before approval.",
            }
        )
        return result
    if item.get("format") in {"carousel", "single", "story", "reel"} and media_count == 0:
        result.update(
            {
                "action": "blocked_by_media",
                "message": "Media/design URLs are required before queue review approval.",
            }
        )
        return result
    if dry_run:
        result["planned"] = {
            "queue_id": item.get("id"),
            "feedback_action": "approve",
            "next_gate": "schedule",
        }
        return result
    feedback = FeedbackIn(
        module="first_publish_queue_review",
        ref_type="publish_queue",
        ref_id=str(item.get("id")),
        action="approve",
        reason="Current first-publish queue item approved by explicit reviewer action.",
        before_text=item.get("caption"),
        tags=["first_publish_queue_review", *audit_tags(session)],
    )
    approved = await save_feedback(feedback)
    result.update(
        {
            "approved": True,
            "result": approved,
            "message": "Current first-publish queue item review-approved. Scheduling and publishing remain separate gates.",
            "after": await first_publish_readiness_payload(),
        }
    )
    return result


