def zh_first_publish_stage_label(key: str | None):
    return {
        "asset_review": "тєЁт«╣УхёС║Дти▓т«ЅтЁежђџУ┐Єт╣ХТЅ╣тЄє",
        "media_ready": "тфњСйЊ/У«ЙУ«Ау┤аТЮљти▓тЄєтцЄтЦй",
        "queue": "ти▓тѕЏт╗║тЈЉтИЃжўЪтѕЌжА╣уЏ«",
        "review_queue": "жўЪтѕЌжА╣уЏ«ти▓т«АТаИТЅ╣тЄє",
        "schedule": "жўЪтѕЌжА╣уЏ«ти▓ТјњуеІ",
        "meta_dry_run": "Meta тЈЉтИЃС╗╗тіАТхІУ»ЋУ┐љУАї",
    }.get(key or "", key or "ТюфуЪЦТГЦжфц")


def zh_first_publish_stage_detail(stage: dict):
    key = stage.get("key")
    evidence = stage.get("evidence") or {}
    if key == "asset_review":
        ready = evidence.get("ready_assets") or 0
        total = evidence.get("asset_count") or 0
        return f"уЏ«тЅЇТюЅ {total} ТЮАтєЁт«╣УхёС║Д№╝ї{ready} ТЮАти▓тљїТЌХТ╗АУХ│т«ЅтЁежђџУ┐ЄтњїТЅ╣тЄєсђѓ"
    if key == "media_ready":
        if evidence.get("required") and not evidence.get("ready"):
            return f"У┐ЎТЮАтєЁт«╣жюђУдЂтфњСйЊ/У«ЙУ«Ау┤аТЮљ№╝їуЏ«тЅЇТюЅ {evidence.get('media_count') or 0} СИфтфњСйЊ URL№╝ЏУ»итЁѕУАЦСИіти▓ТЅ╣тЄєу┤аТЮљсђѓ"
        if evidence.get("required"):
            return f"У┐ЎТЮАтєЁт«╣жюђУдЂтфњСйЊ/У«ЙУ«Ау┤аТЮљ№╝їуЏ«тЅЇТюЅ {evidence.get('media_count') or 0} СИфтфњСйЊ URLсђѓ"
        return "У┐ЎСИфТа╝т╝ЈСИЇт╝║тѕХжюђУдЂтфњСйЊ/У«ЙУ«А URLсђѓ"
    if key == "queue":
        return f"уЏ«тЅЇТюЅ {evidence.get('queue_total') or 0} ТЮАтЈЉтИЃжўЪтѕЌжА╣уЏ«сђѓ"
    if key == "review_queue":
        return f"уЏ«тЅЇТюЅ {evidence.get('review_approved_queue') or 0} ТЮАжўЪтѕЌжА╣уЏ«ти▓жђџУ┐Єт«АТаИсђѓ"
    if key == "schedule":
        return f"уЏ«тЅЇТюЅ {evidence.get('scheduled_queue') or 0} ТЮАжА╣уЏ«ти▓ТјњуеІсђѓ"
    if key == "meta_dry_run":
        blockers = [*evidence.get("facebook_blockers", []), *evidence.get("instagram_blockers", [])]
        return "№╝Џ".join(blockers) if blockers else "Meta dry run ти▓тЄєтцЄтЦйсђѓ"
    return stage.get("detail") or ""


def zh_first_publish_action(next_step: dict):
    key = next_step.get("key")
    if key == "asset_review":
        return "тюе Dashboard уѓ╣тЄ╗сђїтАФтЁЦу┤аТЮљт«АТаИ CSVсђЇ№╝їУ┐ЏтЁЦу┤аТЮљжАхтљјтАФтєЎ reviewer_safety_decision=clear тњї reviewer_review_decision=approved№╝ЏтЈфТюЅуюЪС║║уА«У«цт«ЅтЁетљјТЅЇтЈ»С╗ЦУ┐ЎТаитАФсђѓ"
    if key == "media_ready":
        return "У┐ЏтЁЦ Assets№╝їуѓ╣тЄ╗тйЊтЅЇу┤аТЮљуџё Attach Media№╝їУ┤┤СИіти▓ТЅ╣тЄєуџётЏЙуЅЄ/У«ЙУ«А/УДєжбЉ URL№╝їт╣ХтАФтєЎуЅѕТЮЃТѕќ visual QA тцЄТ│есђѓ"
    if key == "queue":
        return "уѓ╣тЄ╗сђїТјеУ┐Џт«ЅтЁеТГЦжфцсђЇ№╝їу│╗у╗ЪС╝џТііти▓ТЅ╣тЄєСИћт«ЅтЁежђџУ┐ЄуџётєЁт«╣УхёС║ДтіатЁЦтЈЉтИЃжўЪтѕЌсђѓ"
    if key == "review_queue":
        return "СИІУййТѕќтАФтЁЦжўЪтѕЌт«АТаИ CSV№╝їућ▒уюЪС║║Тіі reviewer_action тАФСИ║ approve тљјт»╝тЁЦсђѓ"
    if key == "schedule":
        return "уѓ╣тЄ╗сђїТјеУ┐Џт«ЅтЁеТГЦжфцсђЇ№╝їу│╗у╗ЪС╝џу╗Ўти▓т«АТаИТЅ╣тЄєуџёжўЪтѕЌжА╣уЏ«т«ЅТјњтЈЉтИЃТЌХжЌ┤сђѓ"
    if key == "meta_dry_run":
        return "уѓ╣тЄ╗сђїТјеУ┐Џт«ЅтЁеТГЦжфцсђЇ№╝їу│╗у╗ЪС╝џУ┐љУАї Meta dry run№╝ЏТГБт╝ЈтЈЉтИЃС╗ЇтЈЌ Meta live т╝ђтЁ│С┐ЮТіцсђѓ"
    return "ТїЅжАхжЮбТЈљуц║тцёуљєСИІСИђТГЦсђѓ"


def zh_schedule_audit_summary(payload: dict):
    schedule_stage = next((stage for stage in payload.get("stages") or [] if stage.get("key") == "schedule"), {})
    evidence = schedule_stage.get("evidence") or {}
    status = evidence.get("schedule_audit") or "unknown"
    return {
        "clear": "ТјњуеІУДётѕЎуЏ«тЅЇ clear№╝їтЈ»С╗ЦтюежўЪтѕЌт«АТаИжђџУ┐Єтљјт«ЅТјњтЈЉтИЃТЌХжЌ┤сђѓ",
        "review": "ТјњуеІУДётѕЎжюђУдЂС║║тиЦтцЇТаИ№╝їТјњуеІтЅЇУ»итЁѕуюІ Schedule Auditсђѓ",
        "blocked": "ТјњуеІУДётѕЎтГўтюежў╗убЇ№╝їУ»итЁѕтцёуљє Schedule Audit СИГуџё blockersсђѓ",
    }.get(status, f"ТјњуеІт«АУ«АуіХТђЂ№╝џ{status}")


