@app.post("/operations/import-monthly-carousel-evidence-bridge")
async def import_monthly_carousel_evidence_bridge(
    file: UploadFile = File(...),
    dry_run: bool = Form(True),
    session: dict = Depends(require_review_access),
):
    csv_text = await decode_asset_review_decisions_csv(file)
    reader = csv.DictReader(StringIO(csv_text))
    required = {"asset_id"}
    headers = set(reader.fieldnames or [])
    if not required.issubset(headers):
        missing = sorted(required - headers)
        raise HTTPException(status_code=400, detail={"message": "Monthly evidence bridge CSV is missing required columns.", "missing": missing})

    monthly_assets = await monthly_carousel_asset_list()
    allowed_asset_ids = {str(asset.get("id")) for asset in monthly_assets if asset.get("id")}
    planned = []
    imported = []
    skipped = []
    for index, row in enumerate(reader, start=2):
        asset_id = (row.get("asset_id") or "").strip()
        if not asset_id:
            skipped.append({"row": index, "reason": "Missing asset_id."})
            continue
        if asset_id not in allowed_asset_ids:
            skipped.append({"row": index, "asset_id": asset_id, "reason": "Asset is not part of the monthly carousel source of truth."})
            continue
        existing = await asset_by_id(asset_id)
        if existing is None:
            skipped.append({"row": index, "asset_id": asset_id, "reason": "Asset not found."})
            continue

        doctor_safety = normalize_review_safety_decision(row.get("doctor_safety") or row.get("reviewer_safety_decision"))
        doctor_decision = normalize_asset_review_decision(row.get("doctor_decision") or row.get("reviewer_review_decision"))
        if doctor_safety == "invalid" or doctor_decision == "invalid":
            skipped.append({"row": index, "asset_id": asset_id, "reason": "Doctor decisions must use safety clear/pending/flagged and review approved/review/rejected."})
            continue
        target_safety = doctor_safety or existing.get("compliance_status")
        if doctor_decision == "approved" and target_safety != "clear":
            skipped.append({"row": index, "asset_id": asset_id, "reason": "Approval requires doctor_safety=clear or an already clear asset."})
            continue

        media_urls = parse_media_url_cell(row.get("new_media_urls"))
        invalid_urls = [url for url in media_urls if not str(url).startswith("http")]
        if invalid_urls:
            skipped.append({"row": index, "asset_id": asset_id, "reason": "Media URLs must start with http or https.", "invalid_urls": invalid_urls})
            continue
        visual_qa_status = normalize_visual_qa_status(row.get("visual_qa_status")) if media_urls or row.get("visual_qa_status") else None
        if visual_qa_status == "invalid":
            skipped.append({"row": index, "asset_id": asset_id, "reason": "visual_qa_status must be pending, passed, or needs_work."})
            continue
        reviewer_name = (row.get("reviewer_name") or "").strip()
        review_notes = (row.get("review_notes") or "").strip()
        producer_name = (row.get("producer_name") or "").strip()
        rights_note = (row.get("rights_note") or "").strip()
        production_notes = (row.get("production_notes") or "").strip()
        if doctor_safety is None and doctor_decision is None and not media_urls and not review_notes and not production_notes:
            skipped.append({"row": index, "asset_id": asset_id, "reason": "No doctor decision, media URL, or notes provided."})
            continue

        plan = {
            "row": index,
            "asset_id": asset_id,
            "topic": row.get("topic") or (existing.get("metadata") or {}).get("topic") or "",
            "target_safety": doctor_safety or "",
            "target_review": doctor_decision or "",
            "new_media_count": len(media_urls),
            "visual_qa_status": visual_qa_status or "",
            "reviewer_name": reviewer_name,
            "producer_name": producer_name,
        }
        if dry_run:
            planned.append(plan)
            continue

        applied = []
        review_reason_parts = ["Monthly evidence bridge doctor decision import."]
        if reviewer_name:
            review_reason_parts.append(f"Reviewer: {reviewer_name}.")
        if review_notes:
            review_reason_parts.append(f"Notes: {review_notes}")
        review_reason = " ".join(review_reason_parts)
        if doctor_safety is not None and doctor_safety != existing.get("compliance_status"):
            await update_asset_compliance(asset_id, AssetComplianceIn(compliance_status=doctor_safety, reason=review_reason), session)
            applied.append(f"safety:{doctor_safety}")
        if doctor_decision is not None and doctor_decision != existing.get("review_status"):
            await update_asset_status(asset_id, AssetStatusIn(review_status=doctor_decision, reason=review_reason), session)
            applied.append(f"review:{doctor_decision}")
        if media_urls:
            media_reason_parts = ["Monthly evidence bridge media/design import."]
            if producer_name:
                media_reason_parts.append(f"Producer: {producer_name}.")
            if rights_note:
                media_reason_parts.append(f"Rights: {rights_note}.")
            if production_notes:
                media_reason_parts.append(f"Notes: {production_notes}")
            result = await update_asset_media(
                asset_id,
                AssetMediaIn(
                    media_urls=media_urls,
                    reason=" ".join(media_reason_parts),
                    visual_qa_status=visual_qa_status or "pending",
                    rights_note=rights_note or None,
                    sync_draft_queue=True,
                ),
                session,
            )
            applied.append(f"media:{len(media_urls)}")
            if result.get("synced_queue_count"):
                applied.append(f"synced_queue:{result.get('synced_queue_count')}")
        imported.append({**plan, "applied": applied or ["note_only"]})
    return {
        "dry_run": dry_run,
        "source": "monthly_carousel_evidence_bridge",
        "planned_count": len(planned),
        "imported_count": len(imported),
        "skipped_count": len(skipped),
        "planned": planned,
        "imported": imported,
        "skipped": skipped,
        "message": (
            f"Previewed {len(planned)} monthly evidence bridge row(s), {len(skipped)} skipped."
            if dry_run
            else f"Imported {len(imported)} monthly evidence bridge row(s), {len(skipped)} skipped."
        ),
        "safety": [
            "Bridge import can apply doctor/human review decisions and media/design evidence.",
            "Approval still requires doctor_safety=clear before doctor_decision=approve.",
            "Bridge import does not queue, schedule, publish, update Notion, or call Meta.",
            "Monthly bridge accepts only assets from the Notion monthly carousel source of truth.",
        ],
    }


def normalize_review_safety_decision(value: str | None):
    text = (value or "").strip().lower().replace("_", " ").replace("-", " ")
    if not text:
        return None
    if text in {"clear", "safety clear", "safe", "approved clear", "yes", "y"}:
        return "clear"
    if text in {"pending", "keep pending", "rewrite", "needs work", "needs rewrite", "review", "needs review"}:
        return "pending"
    if text in {"flag", "flagged", "unsafe", "block", "blocked", "no", "n"}:
        return "flagged"
    return "invalid"


def normalize_asset_review_decision(value: str | None):
    text = (value or "").strip().lower().replace("_", " ").replace("-", " ")
    if not text:
        return None
    if text in {"approve", "approved", "yes", "y"}:
        return "approved"
    if text in {"review", "needs work", "needs edits", "needs edit", "rewrite", "pending", "keep pending"}:
        return "review"
    if text in {"reject", "rejected", "no", "n"}:
        return "rejected"
    return "invalid"


def normalize_yes_no(value: str | None):
    text = (value or "").strip().lower().replace("_", " ").replace("-", " ")
    if not text:
        return None
    if text in {"yes", "y", "true", "use", "use polished", "apply", "apply polished", "approved"}:
        return True
    if text in {"no", "n", "false", "do not use", "dont use", "don't use", "edit first", "manual edit", "not yet"}:
        return False
    return "invalid"


def parse_doctor_reply_blocks(reply_text: str):
    blocks = []
    current = {}
    note_lines = []
    doctor_check_aliases = {
        "educational not diagnostic": "doctor_check_educational_not_diagnostic",
        "no guaranteed outcome": "doctor_check_no_guaranteed_outcome",
        "no medication instruction": "doctor_check_no_medication_instruction",
        "mandarin accurate": "doctor_check_mandarin_accurate",
        "cta appropriate": "doctor_check_cta_appropriate",
    }

    def flush():
        if not current and not note_lines:
            return
        item = dict(current)
        if note_lines:
            item["review_notes"] = "\n".join(note_lines).strip()
        blocks.append(item)

    for raw_line in (reply_text or "").splitlines():
        line = raw_line.strip()
        if not line:
            continue
        match = re.match(r"^(asset\s*id|asset_id|id)\s*[:№╝џ]\s*(.+)$", line, flags=re.IGNORECASE)
        if match:
            if current:
                flush()
                current = {}
                note_lines = []
            current["asset_id"] = match.group(2).strip().strip("`")
            continue
        match = re.match(r"^(decision|review)\s*[:№╝џ]\s*(.+)$", line, flags=re.IGNORECASE)
        if match:
            current["reviewer_review_decision"] = match.group(2).strip()
            continue
        match = re.match(r"^(safety|safety decision)\s*[:№╝џ]\s*(.+)$", line, flags=re.IGNORECASE)
        if match:
            current["reviewer_safety_decision"] = match.group(2).strip()
            continue
        match = re.match(r"^(use\s+polished\s+copy|polished\s+copy|apply\s+polish|apply\s+polished\s+copy)\s*[:№╝џ]\s*(.+)$", line, flags=re.IGNORECASE)
        if match:
            current["use_polished_copy"] = match.group(2).strip()
            continue
        match = re.match(r"^(reviewer|reviewer\s*name|doctor|doctor\s*name|т«АТаИС║║|тї╗ућЪтДЊтљЇ)\s*[:№╝џ]\s*(.+)$", line, flags=re.IGNORECASE)
        if match:
            current["reviewer_name"] = match.group(2).strip()
            continue
        match = re.match(r"^(doctor_check_[a-z0-9_]+)\s*[:№╝џ]\s*(.+)$", line, flags=re.IGNORECASE)
        if match:
            current[match.group(1).strip().lower()] = match.group(2).strip()
            continue
        match = re.match(r"^(educational not diagnostic|no guaranteed outcome|no medication instruction|mandarin accurate|cta appropriate)\s*[:№╝џ]\s*(.+)$", line, flags=re.IGNORECASE)
        if match:
            current[doctor_check_aliases[match.group(1).strip().lower()]] = match.group(2).strip()
            continue
        match = re.match(r"^(notes?|reason)\s*[:№╝џ]\s*(.*)$", line, flags=re.IGNORECASE)
        if match:
            note = match.group(2).strip()
            if note:
                note_lines.append(note)
            continue
        if current:
            note_lines.append(line)
    flush()
    return blocks


async def decode_asset_review_decisions_csv(file: UploadFile):
    raw = await file.read()
    if len(raw) > 512_000:
        raise HTTPException(status_code=413, detail="Asset review decision CSV is too large. Keep imports below 512 KB.")
    try:
        return raw.decode("utf-8-sig")
    except UnicodeDecodeError as exc:
        raise HTTPException(status_code=400, detail="Asset review decision CSV must be UTF-8 text.") from exc


MONTHLY_DOCTOR_CHECK_FIELDS = [
    "doctor_check_educational_not_diagnostic",
    "doctor_check_no_guaranteed_outcome",
    "doctor_check_no_medication_instruction",
    "doctor_check_mandarin_accurate",
    "doctor_check_cta_appropriate",
]


def is_affirmative_review_check(value: str | None):
    text = (value or "").strip().lower().replace("_", " ").replace("-", " ")
    return text in {"yes", "y", "true", "pass", "passed", "clear", "ok", "checked", "done", "Тў»", "жђџУ┐Є", "ти▓ТБђТЪЦ"}


def review_import_summary(planned: list[dict], imported: list[dict], skipped: list[dict], dry_run: bool):
    ready_rows = planned if dry_run else imported
    missing_by_field: dict[str, int] = {}
    missing_rows = 0
    outside_source_count = 0
    not_found_count = 0
    invalid_decision_count = 0
    approval_safety_block_count = 0
    for row in skipped:
        reason = row.get("reason") or ""
        missing_evidence = row.get("missing_evidence") or []
        if missing_evidence:
            missing_rows += 1
            for field in missing_evidence:
                missing_by_field[field] = missing_by_field.get(field, 0) + 1
        if "not part of the monthly carousel source of truth" in reason:
            outside_source_count += 1
        if "not found" in reason.lower():
            not_found_count += 1
        if "Decision must use" in reason:
            invalid_decision_count += 1
        if "Approval requires" in reason and "Safety" in reason:
            approval_safety_block_count += 1
    if ready_rows:
        next_step_zh = "тЈ»С╗Цт»╝тЁЦ ready УАї№╝Џт»╝тЁЦтЈфУ«░тйЋтї╗ућЪт«АТаИтњї Safety№╝їСИЇС╝џтЈЉтИЃсђѓ"
    elif missing_rows:
        next_step_zh = "тЁѕУАЦжйљ reviewer_nameсђЂreview_notes тњїТЅђТюЅ doctor_check_*№╝їтєЇжЄЇТќ░жбёУДѕсђѓ"
    elif skipped:
        next_step_zh = "тЁѕС┐«ТГБ skipped rows уџё Asset ID Тѕќ decision тђ╝№╝їтєЇжЄЇТќ░жбёУДѕсђѓ"
    else:
        next_step_zh = "У┐ўТ▓АТюЅтЈ»тцёуљєуџётї╗ућЪт«АТаИУАїсђѓ"
    return {
        "ready_count": len(ready_rows),
        "skipped_count": len(skipped),
        "missing_evidence_count": missing_rows,
        "missing_by_field": missing_by_field,
        "outside_source_count": outside_source_count,
        "not_found_count": not_found_count,
        "invalid_decision_count": invalid_decision_count,
        "approval_safety_block_count": approval_safety_block_count,
        "next_step_zh": next_step_zh,
        "safe_to_preview": True,
        "publishing_locked": True,
    }


