def notion_monthly_refresh_workbench_payload():
    now_myt = datetime.now(timezone(timedelta(hours=8)))
    refresh_day = int(NOTION_CAROUSEL_SOURCE["monthly_refresh_day"])
    refresh_this_month = now_myt.replace(day=refresh_day, hour=0, minute=0, second=0, microsecond=0)
    if now_myt.day >= refresh_day:
        active_refresh = refresh_this_month
        if now_myt.month == 12:
            next_refresh = now_myt.replace(year=now_myt.year + 1, month=1, day=refresh_day, hour=0, minute=0, second=0, microsecond=0)
        else:
            next_refresh = now_myt.replace(month=now_myt.month + 1, day=refresh_day, hour=0, minute=0, second=0, microsecond=0)
    else:
        if now_myt.month == 1:
            active_refresh = now_myt.replace(year=now_myt.year - 1, month=12, day=refresh_day, hour=0, minute=0, second=0, microsecond=0)
        else:
            active_refresh = now_myt.replace(month=now_myt.month - 1, day=refresh_day, hour=0, minute=0, second=0, microsecond=0)
        next_refresh = refresh_this_month
    due_today = now_myt.day == refresh_day
    days_since_active_refresh = (now_myt.date() - active_refresh.date()).days
    days_until_next_refresh = (next_refresh.date() - now_myt.date()).days
    if due_today:
        refresh_window_label = "refresh_due_today"
    elif 0 < days_since_active_refresh <= 2:
        refresh_window_label = "fresh_refresh_window"
    elif days_until_next_refresh <= 3:
        refresh_window_label = "prepare_next_refresh"
    else:
        refresh_window_label = "active_monthly_cycle"
    return {
        "source": notion_carousel_source_payload(),
        "generated_at_myt": now_myt.isoformat(),
        "refresh_day": refresh_day,
        "active_cycle_start": active_refresh.date().isoformat(),
        "next_refresh_date": next_refresh.date().isoformat(),
        "days_since_active_refresh": days_since_active_refresh,
        "days_until_next_refresh": days_until_next_refresh,
        "refresh_window_label": refresh_window_label,
        "connector_status": {
            "schema": NOTION_CAROUSEL_SOURCE.get("direct_connector_schema"),
            "schema_verified_at": NOTION_CAROUSEL_SOURCE.get("direct_connector_schema_verified_at"),
            "row_query": NOTION_CAROUSEL_SOURCE.get("direct_connector_row_query"),
            "fallback": NOTION_CAROUSEL_SOURCE.get("app_sync_mode"),
            "reason": NOTION_CAROUSEL_SOURCE.get("connector_fallback_reason"),
        },
        "status": "refresh_due_today" if due_today else "active_monthly_cycle",
        "cycle_label": f"{active_refresh.strftime('%Y-%m-%d')} monthly Notion cycle",
        "notion_filters": [
            {
                "purpose": "image_ai_work_queue",
                "rules": [
                    "Overall Status is not Published",
                    "Carousel Image Status equals Not Started",
                    "Carousel Slide Plan is not empty",
                    "Topic ID is present",
                ],
                "required_fields": NOTION_CAROUSEL_SOURCE["fields"],
            },
            {
                "purpose": "caption_ai_work_queue",
                "rules": [
                    "Overall Status is not Published",
                    "Caption Status equals Not Started",
                    "Carousel Slide Plan is not empty",
                    "Topic ID is present",
                ],
                "required_fields": NOTION_CAROUSEL_SOURCE["fields"],
            },
        ],
        "operator_checklist": [
            "Open the Notion master database after the monthly 19th refresh.",
            "Confirm the schema still matches the verified fields; if direct row query is unavailable, export the current Notion view as CSV.",
            "Confirm the current month rows have unique Topic ID values.",
            "Skip rows where Overall Status = Published.",
            "For image work, select only rows where Carousel Image Status = Not Started.",
            "Before image generation starts, set Carousel Image Status = In Progress in Notion.",
            "Import or sync the existing Notion row into DREC Content OS using Topic ID.",
            "Generate slides from Carousel Slide Plan without rewriting the educational structure.",
            "After image files are ready, set Carousel Image Status = Ready for Review in Notion.",
            "Do not touch Caption Status unless this run is specifically for caption AI.",
        ],
        "stop_rules": [
            "Do not create new Notion rows from DREC Content OS.",
            "Do not generate duplicate topics if the Topic ID already exists locally.",
            "Do not work on Published rows.",
            "Do not use miracle-cure, guaranteed reversal, fear-based, or course-selling language.",
            "Do not make Slide 1 an explanation slide; Slide 1 is the cover hook only.",
            "Do not assume live row sync is available until the connector row-query gate no longer reports enterprise_plan_required.",
        ],
        "next_action": "Run the Notion image queue check, update selected rows to In Progress, then import/sync rows by Topic ID.",
    }


async def notion_monthly_refresh_status_payload():
    workbench = notion_monthly_refresh_workbench_payload()
    assets = await monthly_carousel_asset_list()
    all_assets = await fetch_asset_list(500)
    active_start = datetime.fromisoformat(workbench["active_cycle_start"]).replace(tzinfo=MYT)
    active_start_utc = active_start.astimezone(timezone.utc)
    topic_ids = [monthly_carousel_topic_id(asset) for asset in assets if monthly_carousel_topic_id(asset)]
    topic_id_counts: dict[str, int] = {}
    for topic_id in topic_ids:
        topic_id_counts[topic_id] = topic_id_counts.get(topic_id, 0) + 1
    duplicate_topic_ids = sorted([topic_id for topic_id, count in topic_id_counts.items() if count > 1])
    notion_carousel_without_topic = [
        asset for asset in all_assets
        if asset.get("format") == "carousel"
        and ((asset.get("metadata") or {}).get("notion_source") or {})
        and not monthly_carousel_topic_id(asset)
    ]
    created_dates = [parse_datetime(asset.get("created_at")) for asset in assets]
    created_dates = [date for date in created_dates if date]
    imported_since_refresh = [
        asset for asset in assets
        if (parse_datetime(asset.get("created_at")) or datetime.min.replace(tzinfo=timezone.utc)) >= active_start_utc
    ]
    image_status_counts: dict[str, int] = {}
    overall_status_counts: dict[str, int] = {}
    caption_status_counts: dict[str, int] = {}
    for asset in assets:
        notion_source = ((asset.get("metadata") or {}).get("notion_source") or {})
        image_status = notion_source.get("carousel_image_status") or "unknown"
        overall_status = notion_source.get("overall_status") or "unknown"
        caption_status = notion_source.get("caption_status") or "unknown"
        image_status_counts[image_status] = image_status_counts.get(image_status, 0) + 1
        overall_status_counts[overall_status] = overall_status_counts.get(overall_status, 0) + 1
        caption_status_counts[caption_status] = caption_status_counts.get(caption_status, 0) + 1
    diagnostics = []
    if duplicate_topic_ids:
        diagnostics.append({
            "status": "blocked",
            "label": "Duplicate Topic ID detected",
            "detail": ", ".join(duplicate_topic_ids),
        })
    if notion_carousel_without_topic:
        diagnostics.append({
            "status": "blocked",
            "label": "Notion carousel asset missing Topic ID",
            "detail": f"{len(notion_carousel_without_topic)} asset(s) have notion_source metadata but no Topic ID.",
        })
    if imported_since_refresh:
        diagnostics.append({
            "status": "ready",
            "label": "Current cycle import evidence",
            "detail": f"{len(imported_since_refresh)} asset(s) created after {workbench.get('active_cycle_start')} MYT.",
        })
    else:
        diagnostics.append({
            "status": "waiting",
            "label": "Current cycle import evidence",
            "detail": "No local monthly carousel asset was created after the active refresh date.",
        })
    if workbench.get("status") == "refresh_due_today":
        status = "refresh_due_today"
        next_action = "Open the Notion database today, confirm refreshed rows, then import/sync existing rows by Topic ID."
    elif duplicate_topic_ids or notion_carousel_without_topic:
        status = "local_source_needs_cleanup"
        next_action = "Fix local Topic ID problems before creating images, captions, or queue items for this monthly cycle."
    elif not assets:
        status = "no_local_monthly_assets"
        next_action = "Import/sync the current Notion monthly rows before generating carousel images or captions."
    elif not imported_since_refresh:
        status = "needs_rescan_after_refresh"
        next_action = "Re-scan Notion because the current monthly cycle started after the latest local monthly import."
    else:
        status = "local_cycle_active"
        next_action = "Continue the visible monthly gates: doctor review, production QA, queue review, schedule, handoff, and learning."
    latest_local_import_at = max(created_dates).isoformat() if created_dates else None
    return {
        "source": notion_carousel_source_payload(),
        "status": status,
        "generated_at_myt": workbench.get("generated_at_myt"),
        "active_cycle_start": workbench.get("active_cycle_start"),
        "next_refresh_date": workbench.get("next_refresh_date"),
        "days_since_active_refresh": workbench.get("days_since_active_refresh"),
        "days_until_next_refresh": workbench.get("days_until_next_refresh"),
        "refresh_window_label": workbench.get("refresh_window_label"),
        "local_monthly_asset_count": len(assets),
        "imported_since_refresh_count": len(imported_since_refresh),
        "latest_local_import_at": latest_local_import_at,
        "topic_ids": topic_ids,
        "duplicate_topic_ids": duplicate_topic_ids,
        "missing_topic_id_count": len(notion_carousel_without_topic),
        "diagnostics": diagnostics,
        "image_status_counts": image_status_counts,
        "overall_status_counts": overall_status_counts,
        "caption_status_counts": caption_status_counts,
        "next_action": next_action,
        "evidence": [
            f"Active monthly cycle starts on {workbench.get('active_cycle_start')} MYT.",
            f"Current date is {workbench.get('days_since_active_refresh')} day(s) after the active refresh; next refresh is in {workbench.get('days_until_next_refresh')} day(s).",
            f"{len(assets)} non-published local monthly carousel asset(s) are visible.",
            f"{len(imported_since_refresh)} local monthly asset(s) were created after this cycle start.",
            f"{len(duplicate_topic_ids)} duplicate Topic ID value(s) were detected locally.",
            f"{len(notion_carousel_without_topic)} Notion carousel asset(s) are missing Topic ID.",
            "This check is read-only and does not query, edit, create, schedule, publish, or call Meta.",
        ],
        "safety": [
            "Use Topic ID as the unique identifier.",
            "Do not create duplicate Notion rows.",
            "Skip Notion rows where Overall Status = Published.",
            "Before image generation, set Carousel Image Status to In Progress in Notion.",
            "After images are ready, set Carousel Image Status to Ready for Review in Notion.",
        ],
    }


