def extract_notion_cover_hook(slide_plan: str, fallback: str):
    match = re.search(r"Big Title/Hook:\s*(.+?)(?:<br>|\n|Visual Element:)", slide_plan or "", flags=re.IGNORECASE | re.DOTALL)
    if not match:
        match = re.search(r"Big Title:\s*(.+?)(?:<br>|\n|Explanation Text:)", slide_plan or "", flags=re.IGNORECASE | re.DOTALL)
    if not match:
        return fallback
    return re.sub(r"\s+", " ", html.unescape(match.group(1))).strip() or fallback


def clean_notion_slide_text(value: str | None):
    text = html.unescape(value or "")
    text = re.sub(r"<br\s*/?>", "\n", text, flags=re.IGNORECASE)
    text = re.sub(r"<[^>]+>", "", text)
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    lines = [re.sub(r"\s+", " ", line).strip() for line in text.split("\n")]
    return "\n".join([line for line in lines if line])


def notion_field(block: str, label: str, stop_labels: list[str]):
    stop_pattern = "|".join(re.escape(item) for item in stop_labels)
    pattern = rf"{re.escape(label)}\s*(.*?)(?=\n(?:{stop_pattern})\s*|$)"
    match = re.search(pattern, block, flags=re.IGNORECASE | re.DOTALL)
    if not match:
        return ""
    return re.sub(r"\n{2,}", "\n", match.group(1)).strip()


def parse_notion_carousel_slide_plan(slide_plan: str):
    clean = clean_notion_slide_text(slide_plan)
    if not clean:
        return []
    matches = list(re.finditer(r"(?im)^Slide\s+(\d+)\b", clean))
    slides = []
    labels = [
        "Big Title/Hook:",
        "Big Title:",
        "Explanation Text:",
        "Highlighted Keywords:",
        "Visual Element:",
        "Bottom Takeaway/Teaser:",
    ]
    for index, match in enumerate(matches):
        slide_number = int(match.group(1))
        start = match.end()
        end = matches[index + 1].start() if index + 1 < len(matches) else len(clean)
        block = clean[start:end].strip()
        title = notion_field(block, "Big Title/Hook:", labels) if slide_number == 1 else ""
        if not title:
            title = notion_field(block, "Big Title:", labels)
        explanation = "" if slide_number == 1 else notion_field(block, "Explanation Text:", labels)
        keywords_text = notion_field(block, "Highlighted Keywords:", labels)
        visual = notion_field(block, "Visual Element:", labels)
        takeaway = "" if slide_number == 1 else notion_field(block, "Bottom Takeaway/Teaser:", labels)
        keywords = [item.strip() for item in re.split(r"[,№╝їсђЂ]", keywords_text) if item.strip()]
        if not title and not explanation and not visual:
            continue
        slides.append(
            {
                "slide": slide_number,
                "title": title,
                "body": explanation,
                "highlighted_keywords": keywords[:4],
                "visual_note": visual,
                "bottom_takeaway": takeaway,
                "source": "notion_carousel_slide_plan",
            }
        )
    return slides


async def find_existing_notion_brief(topic_id: str):
    for brief in await fetch_content_brief_list(200):
        beats = brief.get("structure_beats") or {}
        if isinstance(beats, str):
            try:
                beats = json.loads(beats)
            except json.JSONDecodeError:
                beats = {}
        source = beats.get("notion_source") or {}
        if source.get("topic_id") == topic_id:
            return brief
    return None


async def find_existing_notion_asset(topic_id: str):
    for asset in await fetch_asset_list(200):
        metadata = asset.get("metadata") or {}
        if isinstance(metadata, str):
            try:
                metadata = json.loads(metadata)
            except json.JSONDecodeError:
                metadata = {}
        source = metadata.get("notion_source") or {}
        if source.get("topic_id") == topic_id:
            return asset
    return None


def notion_row_to_brief(row: NotionCarouselRowIn):
    topic = row.mandarin_topic_title.strip()
    hook = extract_notion_cover_hook(row.carousel_slide_plan, topic)
    slides = parse_notion_carousel_slide_plan(row.carousel_slide_plan)
    return ContentBriefIn(
        channel="organic",
        format="carousel",
        pillar="metabolic_education",
        funnel_stage="TOFU",
        awareness_stage=row.content_stage or "notion_monthly_plan",
        topic=topic,
        hook_primary=hook,
        hook_alt1=row.english_topic_title,
        hook_alt2=f"Topic ID: {row.topic_id}",
        structure_beats={
            "source": "notion_master_content_plan",
            "notion_source": {
                "database_url": NOTION_CAROUSEL_SOURCE["database_url"],
                "data_source_url": NOTION_CAROUSEL_SOURCE["data_source_url"],
                "topic_id": row.topic_id,
                "notion_url": row.notion_url,
                "overall_status": row.overall_status,
                "carousel_image_status": row.carousel_image_status,
                "caption_status": row.caption_status,
                "planned_posting_date": row.planned_posting_date,
                "day": row.day,
            },
            "carousel_slide_plan": row.carousel_slide_plan,
            "slides": slides,
            "slide_rules": NOTION_CAROUSEL_SOURCE["slide_rules"],
            "image_workflow_rules": NOTION_CAROUSEL_SOURCE["status_rules"],
        },
        style_hint="dr_chang_readable_green",
        cta_type="soft_save_share_follow",
        target_signal="organic saves, shares, follows, qualified comments",
        language="zh",
        compliance_notes="Education only. Avoid miracle cure, guaranteed reversal, fear-based claims, medication instructions, diagnosis, or direct course-selling language.",
    )


