VIDEO_HARD_STOP_RULES = [
    "DREC Cut automation remains off until a real video editor workflow is built and reviewed.",
    "Do not publish reels with private, expired, unapproved, or patient-identifiable media URLs.",
    "Do not treat AI-generated scripts as medical approval.",
    "Do not schedule a reel until asset review is approved and compliance status is clear.",
]


def video_job_blockers(asset: dict, approved_video_count: int):
    metadata = asset.get("metadata") or {}
    script = metadata.get("reel_script") or []
    media_urls = [str(url) for url in asset.get("media_urls") or [] if url]
    blockers = []
    if asset.get("format") != "reel":
        blockers.append("Only reel assets enter Video Studio.")
    if not script:
        blockers.append("Needs a reel script.")
    if asset.get("review_status") != "approved":
        blockers.append("Needs human asset approval.")
    if asset.get("compliance_status") != "clear":
        blockers.append("Needs compliance clear.")
    if not media_urls and not approved_video_count:
        blockers.append("Needs approved vertical video media or a source clip.")
    if media_urls and not any(is_video_url(url) for url in media_urls) and not approved_video_count:
        blockers.append("Attached media is not a video URL.")
    return blockers


async def video_studio_readiness_payload():
    assets = await fetch_asset_list(200)
    media_assets = await fetch_media_asset_list(200)
    reel_assets = [asset for asset in assets if asset.get("format") == "reel" and asset.get("review_status") != "rejected"]
    approved_video_media = [
        media
        for media in media_assets
        if media.get("media_type") == "video" and media.get("approval_status") == "approved" and media.get("source_url")
    ]
    jobs = []
    approved_video_count = len(approved_video_media)
    for asset in reel_assets[:20]:
        metadata = asset.get("metadata") or {}
        script = metadata.get("reel_script") or []
        media_urls = [str(url) for url in asset.get("media_urls") or [] if url]
        blockers = video_job_blockers(asset, approved_video_count)
        jobs.append(
            {
                "asset_id": asset.get("id"),
                "topic": metadata.get("topic") or "Reel asset",
                "channel": asset.get("channel"),
                "review_status": asset.get("review_status"),
                "compliance_status": asset.get("compliance_status"),
                "style_key": metadata.get("style_key") or "reel_script_v1",
                "script_beats": len(script),
                "media_count": len(media_urls),
                "has_video_media": any(is_video_url(url) for url in media_urls),
                "approved_video_media_available": approved_video_count,
                "preset": "manual_sop_reel",
                "blockers": blockers,
                "next_step": (
                    "Ready for manual edit handoff; keep DREC Cut automation off."
                    if not blockers
                    else blockers[0]
                ),
            }
        )
    ready_jobs = [job for job in jobs if not job.get("blockers")]
    if ready_jobs:
        overall_status = "ready_for_manual_edit"
    elif reel_assets:
        overall_status = "needs_review_or_media"
    else:
        overall_status = "needs_reel_assets"
    reel_styles = [
        {"key": style.get("key"), "name": style.get("name"), "rules": style.get("rules") or []}
        for style in CREATIVE_STYLE_LIBRARY
        if "reel" in (style.get("formats") or [])
    ]
    return {
        "phase": "future_drec_cut_manual_ready",
        "automation_status": "not_built_yet",
        "overall_status": overall_status,
        "reel_asset_count": len(reel_assets),
        "manual_edit_ready_count": len(ready_jobs),
        "approved_video_media_count": approved_video_count,
        "jobs": jobs,
        "sop_modules": VIDEO_SOP_MODULES,
        "export_specs": {
            "aspect_ratio": "9:16",
            "resolution": "1080x1920",
            "format": "MP4 H.264",
            "audio": "Clear voice, normalized, no distracting background music.",
            "subtitle_safe_area": "Keep subtitles away from platform UI edges.",
        },
        "hard_stop_rules": VIDEO_HARD_STOP_RULES,
        "style_reference": reel_styles,
        "next_step": (
            "Send ready jobs to manual edit and record final assets back into the media library."
            if ready_jobs
            else "Create or approve a reel asset, then attach approved video media before manual editing."
        ),
    }


def reel_storyboard_rows(asset: dict):
    metadata = asset.get("metadata") or {}
    script = metadata.get("reel_script") or []
    if script:
        beats = script
    else:
        beats = [
            {"time": "0-3s", "beat": "Hook", "line": (asset.get("caption") or "").splitlines()[0][:80]},
            {"time": "3-35s", "beat": "Explain", "line": "Use the approved caption as the explanation spine."},
            {"time": "35-45s", "beat": "Close", "line": "Close with save/share and clinician discussion CTA."},
        ]
    rows = []
    for index, beat in enumerate(beats, start=1):
        label = str(beat.get("beat") or f"Beat {index}")
        line = str(beat.get("line") or "").strip()
        rows.append(
            {
                "beat_no": index,
                "timecode": beat.get("time") or "",
                "beat": label,
                "voiceover": line,
                "subtitle": line,
                "visual_direction": reel_visual_direction(label, line, index),
                "edit_note": reel_edit_note(label, index),
            }
        )
    return rows


def reel_visual_direction(label: str, line: str, index: int):
    lowered = label.lower()
    if index == 1 or "hook" in lowered:
        return "тї╗ућЪТГБжЮбтЇіУ║Ф№╝їDREC УЊЮу╗┐УЃїТЎ»№╝їт▒Јт╣ЋтидСЙДТћЙтцДТаЄжбў№╝ЏСИЇУдЂТћЙТЂљтљЊућ╗жЮбсђѓ"
    if "context" in lowered:
        return "тѕЄтѕ░уЎйТЮ┐Тѕќу«ђТ┤ЂТЋ░ТЇ«тЇА№╝їТўЙуц║РђюС╣аТЃ» + ТЋ░ТЇ« + УХІті┐РђЮ№╝їТќЄтГЌСИЇУдЂУХЁУ┐ЄСИцУАїсђѓ"
    if "mechanism" in lowered:
        return "уће HbA1cсђЂжЦГтљјУАђу│ќсђЂУЁ░тЏ┤УХІті┐уГЅСИГТђДтЏЙТаЄУЙЁтіЕУДБжЄі№╝їСИЇСй┐ућетцИт╝атЅЇтљјт»╣Т»ћсђѓ"
    if "observation" in lowered or "practical" in lowered:
        return "т▒Ћуц║У«░тйЋТюгсђЂУАђу│ќС╗фсђЂжцљуЏўТѕќтцЇУ»іУхёТќЎуџёт«ЅтЁе B-roll№╝ЏтЈфућети▓ТјѕТЮЃу┤аТЮљсђѓ"
    if "close" in lowered:
        return "тї╗ућЪТћХт░Й№╝їт║ЋжЃетГЌт╣ЋТЈљуц║РђюТћХУЌЈ/СИІТгАтцЇУ»ітЈ»тЈѓУђЃРђЮ№╝ЏжЂ┐тЁЇуЏ┤ТјЦжћђтћ«сђѓ"
    return "Сй┐ућетї╗ућЪУ«▓УДБ + у«ђТ┤Ђтї╗уќЌтЏЙтйб№╝їУДєУДЅТћ»ТїЂтЈБТњГ№╝їСИЇТЏ┐С╗БУДБжЄісђѓ"


def reel_edit_note(label: str, index: int):
    if index == 1:
        return "тЅЇСИЅуДњтГЌт╣ЋУдЂтцД№╝їС┐ЮуЋЎС║║уЅЕую╝уЦъТјЦУДд№╝ЏУіѓтЦЈТИЁТЦџСйєСИЇУдЂтѕХжђауёдУЎЉсђѓ"
    if "close" in label.lower():
        return "у╗Њт░ЙС┐ЮуЋЎ 1 уДњ DREC logo/тЁ│Т│еТЈљуц║№╝ЏCTA УдЂУй»№╝їСИЇТЅ┐У»║жђєУйгу╗ЊТъюсђѓ"
    return "Т»Ј 4-6 уДњтЈ»ТЇбСИђТгАжЋютц┤№╝ЏтГЌт╣ЋтюеСИГСИІт«ЅтЁетї║№╝їтГЌтЈиТЅІТю║тЈ»У»╗сђѓ"


def markdown_table_cell(value):
    return str(value or "").replace("|", "\\|").replace("\n", "<br>").strip()


async def video_manual_reel_handoff_payload():
    payload = await video_studio_readiness_payload()
    assets = await fetch_asset_list(200)
    queue_items = await fetch_publish_queue_items(200)
    queue_by_asset = {
        str(item.get("asset_id")): item
        for item in queue_items
        if item.get("asset_id") and item.get("format") == "reel" and item.get("status") in {"draft", "scheduled"}
    }
    handoff_jobs = []
    for job in payload.get("jobs") or []:
        asset_id = str(job.get("asset_id") or "")
        asset = next((item for item in assets if str(item.get("id")) == asset_id), {})
        queue_item = queue_by_asset.get(asset_id, {})
        rows = reel_storyboard_rows(asset)
        handoff_jobs.append(
            {
                **job,
                "queue_id": queue_item.get("id"),
                "planned_slot": queue_item.get("planned_slot"),
                "queue_status": queue_item.get("status"),
                "caption": queue_item.get("caption") or asset.get("caption"),
                "storyboard_rows": rows,
                "delivery_requirements": [
                    "Export one public or signed MP4 URL before this item can enter publishing handoff.",
                    "Vertical 1080x1920 MP4 H.264, clear voice, readable Mandarin subtitles.",
                    "Use only DREC-owned, licensed, patient-consented, or approved generated visuals.",
                    "Do not add miracle, guaranteed reversal, fear-based, or direct course-selling claims.",
                    "After final QA, attach the video URL to the asset media field; do not publish from the video handoff.",
                ],
            }
        )
    return {
        "phase": "manual_reel_handoff",
        "mode": "read_only_video_production_handoff",
        "job_count": len(handoff_jobs),
        "ready_for_edit_count": sum(1 for item in handoff_jobs if not item.get("blockers")),
        "blocked_count": sum(1 for item in handoff_jobs if item.get("blockers")),
        "jobs": handoff_jobs,
        "safety": [
            "This handoff does not publish to Facebook or Instagram.",
            "This handoff does not create a final video file automatically.",
            "A real MP4 URL must be attached before Reel publishing handoff can proceed.",
            "Meta live publishing remains locked behind separate environment switches.",
        ],
        "next_step": "Send blocked Reel jobs to manual video production, then attach the final approved MP4 URL back to the asset.",
    }


