def reel_script_lines_from_caption(caption: str | None):
    text = (caption or "").strip()
    if not text:
        return [
            "Hook№╝џСИ║С╗ђС╣ѕТћ╣тќёС╗БУ░бУдЂтЁѕуюІС╣аТЃ»тњїТЋ░ТЇ«№╝їУђїСИЇТў»тЦЄУ┐╣сђѓ",
            "С╗БУ░буіХТђЂжђџтИИУдЂуюІУХІті┐№╝їСИЇТў»тЈфуюІСИђТгАТЋ░тГЌсђѓ",
            "ТііУАђу│ќсђЂУЁ░тЏ┤сђЂHbA1c тњїжЦГтљјтЈЇт║ћТћЙтюеСИђУхиуљєУДБсђѓ",
            "тдѓТъюТЋ░тГЌжЋ┐ТюЪт╝ѓтИИ№╝їтИдуЮђУ«░тйЋтњїтї╗ућЪУ«еУ«║сђѓ",
            "У┐ЎСИЇТў»У»іТќГТѕќСИфС║║Т▓╗уќЌт╗║У««сђѓ",
        ]
    lines = []
    for raw_line in text.splitlines():
        clean = dr_chang_slide_text(raw_line)
        if clean:
            lines.append(clean)
    if len(lines) <= 1:
        lines = [item.strip() for item in re.split(r"[сђѓ№╝Ђ№╝Ъ!?]\s*", text) if item.strip()]
    return [line for line in lines if line][:8]


def srt_timestamp(seconds: int):
    minutes, sec = divmod(max(0, int(seconds)), 60)
    hours, minutes = divmod(minutes, 60)
    return f"{hours:02d}:{minutes:02d}:{sec:02d},000"


def reel_srt_from_lines(lines: list[str], seconds_per_line: int = 5):
    chunks = []
    for index, line in enumerate(lines, start=1):
        start = (index - 1) * seconds_per_line
        end = start + seconds_per_line
        chunks.extend(
            [
                str(index),
                f"{srt_timestamp(start)} --> {srt_timestamp(end)}",
                line,
                "",
            ]
        )
    return "\n".join(chunks)


def reel_storyboard_frame_png(item: dict, line: str, index: int, total: int):
    deep_green = "#0A463F"
    off_white = "#FBF7EF"
    deep_red = "#C0392B"
    gold = "#F5C518"
    slate = "#1D2935"
    image = Image.new("RGB", (1080, 1920), deep_green)
    draw = ImageDraw.Draw(image)
    draw.ellipse((690, 120, 1210, 640), fill="#155F55")
    draw.ellipse((-240, 1450, 420, 2110), fill="#123E38")
    draw.arc((92, 1260, 520, 1690), 195, 348, fill=gold, width=18)
    draw_dr_chang_logo(draw, image)
    draw.text((870, 80), f"{index}/{total}", font=first_publish_font(34, bold=True), fill=off_white)
    paste_image_contain(image, DR_CHANG_DOCTOR_PRESENTING_PATH if index == 1 else DR_CHANG_DOCTOR_STANDING_PATH, (620, 250, 1045, 1120), opacity=0.95)
    draw.rounded_rectangle((70, 970, 1010, 1605), radius=36, fill=off_white)
    draw.rectangle((104, 1034, 120, 1510), fill=gold)
    heading = "Reel Hook" if index == 1 else "Key Beat"
    draw.text((150, 1040), heading, font=first_publish_font(42, bold=True), fill=deep_red if index == 1 else deep_green)
    y = 1140
    for text_line in wrap_draw_text(draw, line, first_publish_font(50, bold=True), 780, 5):
        draw.text((150, y), text_line, font=first_publish_font(50, bold=True), fill=deep_green)
        y += 70
    draw.rounded_rectangle((120, 1528, 960, 1610), radius=18, fill="white")
    draw.text((150, 1552), "тГЌт╣ЋтцДсђЂУ»ГТ░ћуе│сђЂСИЇУдЂТЅ┐У»║уќЌТЋѕ", font=first_publish_font(28, bold=True), fill=slate)
    draw.text((86, 1770), "тї╗ућЪ Chang", font=first_publish_font(34, bold=True), fill=off_white)
    draw.text((86, 1825), "СИђУѕгтЂЦт║иТЋЎУѓ▓№╝їСИЇС╗БТЏ┐СИфС║║У»іТќГТѕќТ▓╗уќЌт╗║У««сђѓ", font=first_publish_font(24), fill="#DDEBE6")
    output = BytesIO()
    image.save(output, format="PNG", optimize=True)
    return output.getvalue()


def reel_draft_public_url(request: Request, item: dict):
    queue_id = item.get("id")
    if not queue_id:
        return ""
    return f"{request_public_base_url(request)}/public/reel-drafts/{queue_id}.mp4"


async def blocked_reel_queue_item(queue_id: str):
    closeout = await publishing_closeout_payload(100)
    for item in closeout.get("scheduled_blocked") or []:
        if str(item.get("id") or "") == str(queue_id) and item.get("format") == "reel":
            return item
    return None


def ffmpeg_executable():
    exe = shutil.which("ffmpeg")
    if exe:
        return exe
    raise HTTPException(status_code=503, detail="FFmpeg is not available in this runtime.")


def reel_draft_mp4_bytes(item: dict):
    lines = reel_script_lines_from_caption(item.get("caption"))[:6]
    if not lines:
        raise HTTPException(status_code=404, detail="No Reel script is available.")
    total = len(lines)
    with tempfile.TemporaryDirectory() as temp_dir:
        temp_path = Path(temp_dir)
        frame_paths = []
        for index, line in enumerate(lines, start=1):
            frame_path = temp_path / f"frame-{index:02d}.png"
            frame_path.write_bytes(reel_storyboard_frame_png(item, line, index, total))
            frame_paths.append(frame_path)
        concat_path = temp_path / "frames.txt"
        concat_lines = []
        for frame_path in frame_paths:
            concat_lines.append(f"file '{frame_path.as_posix()}'")
            concat_lines.append("duration 5")
        concat_lines.append(f"file '{frame_paths[-1].as_posix()}'")
        concat_path.write_text("\n".join(concat_lines) + "\n", encoding="utf-8")
        output_path = temp_path / "drec-reel-draft.mp4"
        command = [
            ffmpeg_executable(),
            "-hide_banner",
            "-loglevel",
            "error",
            "-y",
            "-f",
            "concat",
            "-safe",
            "0",
            "-i",
            str(concat_path),
            "-c:v",
            "libx264",
            "-vf",
            "fps=30,format=yuv420p",
            "-movflags",
            "+faststart",
            str(output_path),
        ]
        try:
            subprocess.run(command, check=True, capture_output=True, timeout=45)
        except subprocess.TimeoutExpired as exc:
            raise HTTPException(status_code=504, detail="Reel draft generation timed out.") from exc
        except subprocess.CalledProcessError as exc:
            detail = (exc.stderr or b"").decode("utf-8", errors="ignore")[:500] or "Reel draft generation failed."
            raise HTTPException(status_code=500, detail=detail) from exc
        return output_path.read_bytes()


