def build_completion_status(loop, workflow, security, automation):
    summary = workflow.get("summary") or {}
    automation_summary = (automation or {}).get("summary") or {}
    automation_gates = {item.get("key"): item for item in (automation or {}).get("gates") or []}
    brief_count = int(summary.get("brief_count") or loop.get("brief_count") or 0)
    asset_count = int(summary.get("asset_count") or loop.get("asset_count") or 0)
    media_count = int(summary.get("media_count") or loop.get("media_count") or 0)
    outcome_count = int(summary.get("outcome_count") or loop.get("outcome_count") or 0)
    weight_count = int(loop.get("weight_count") or 0)
    ready_asset_count = int(summary.get("queue_ready_asset_count") or automation_summary.get("ready_assets") or 0)
    queue_total = int(summary.get("queue_total") or automation_summary.get("queue_total") or 0)
    scheduled_queue = int(automation_summary.get("scheduled_queue") or 0)
    published_queue = int(automation_summary.get("published_queue") or 0)
    meta_ready = (automation_gates.get("meta") or {}).get("status") == "ready"
    data_connection = security.get("data_connection") or {}
    data_backend_ready = (security.get("data_backend") or data_connection.get("data_backend")) in {"postgres", "supabase_rest"}
    browser_protected = security.get("direct_browser_supabase") == "disabled_by_design"
    strict_security_ready = bool(security.get("rls_hardening_ready"))

    first_cycle_score = 0
    if asset_count:
        first_cycle_score += 4
    if ready_asset_count:
        first_cycle_score += 4
    if queue_total:
        first_cycle_score += 3
    if scheduled_queue:
        first_cycle_score += 2
    if published_queue:
        first_cycle_score += 1

    if published_queue:
        first_cycle_status = "ready"
        first_cycle_detail = f"{published_queue} published queue item(s) have evidence; record metrics and roll learning forward."
    elif scheduled_queue:
        first_cycle_status = "waiting"
        first_cycle_detail = f"{scheduled_queue} scheduled item(s) are ready for manual publishing evidence; after a human posts, record the Meta post ID or manual label, then add metrics."
    elif queue_total:
        first_cycle_status = "waiting"
        first_cycle_detail = f"{queue_total} queue item(s) exist; finish queue review approval and scheduling before manual handoff."
    elif ready_asset_count:
        first_cycle_status = "waiting"
        first_cycle_detail = f"{ready_asset_count} approved clear asset(s) can enter the publishing queue."
    elif asset_count:
        first_cycle_status = "waiting"
        first_cycle_detail = "Draft assets exist; explicit doctor or human approval and Safety clear are still required."
    else:
        first_cycle_status = "open"
        first_cycle_detail = "Create one safe draft asset before starting the first publish cycle."

    items = [
        completion_item(
            "core_app",
            "Core app and API are live",
            8,
            8,
            "ready",
            "The protected API and browser UI are deployed and responding.",
        ),
        completion_item(
            "weekly_planning",
            "Weekly planning",
            10 if brief_count else 0,
            10,
            "ready" if brief_count else "open",
            f"{brief_count} brief(s) are available.",
        ),
        completion_item(
            "draft_assets",
            "Draft asset pipeline",
            10 if asset_count else 0,
            10,
            "ready" if asset_count else "open",
            f"{asset_count} draft asset(s) exist.",
        ),
        completion_item(
            "media_preparation",
            "Media preparation",
            6 if media_count else 0,
            6,
            "ready" if media_count else "open",
            f"{media_count} media item(s) are registered.",
        ),
        completion_item(
            "review_approval",
            "Review and approval path",
            8 if ready_asset_count else 4 if asset_count else 0,
            8,
            "ready" if ready_asset_count else "waiting",
            "Human approval is still required for the first clear asset." if not ready_asset_count else f"{ready_asset_count} approved clear asset(s) can enter queue.",
        ),
        completion_item(
            "scheduling_handoff",
            "Scheduling and handoff path",
            6 if scheduled_queue else 3 if queue_total or asset_count else 0,
            6,
            "ready" if scheduled_queue else "waiting",
            "Queue and schedule are ready as tooling, but need an approved item." if not scheduled_queue else f"{scheduled_queue} item(s) are scheduled.",
        ),
        completion_item(
            "learning_loop",
            "Learning loop",
            8 if weight_count else 6 if outcome_count else 0,
            8,
            "ready" if outcome_count else "open",
            f"{outcome_count} outcome(s) and {weight_count} active weight(s) are available.",
        ),
        completion_item(
            "meta_workers",
            "Meta test workers",
            7 if meta_ready else 0,
            8,
            "ready_for_testing" if meta_ready else "waiting",
            (automation_gates.get("meta") or {}).get("detail") or "Meta workers remain locked until controlled testing.",
        ),
        completion_item(
            "data_connection",
            "Server data connection",
            4 if data_backend_ready and browser_protected else 0,
            4,
            "ready" if data_backend_ready and browser_protected else "blocked",
            data_connection.get("summary") or "Server data connection evidence is missing.",
        ),
        completion_item(
            "security_hardening",
            "Security hardening",
            4 if strict_security_ready else 0,
            4,
            "ready" if strict_security_ready else "blocked",
            security.get("next_step") or "Add service-role key before strict RLS hardening.",
        ),
        completion_item(
            "first_publish_cycle",
            "First publish cycle",
            first_cycle_score,
            14,
            first_cycle_status,
            first_cycle_detail,
        ),
    ]
    total_score = sum(item["score"] for item in items)
    total_weight = sum(item["weight"] for item in items)
    percent = round(total_score * 100 / total_weight) if total_weight else 0
    first_cycle_percent = round(first_cycle_score * 100 / 14)
    blockers = []
    if not ready_asset_count:
        blockers.append("First asset still needs explicit doctor or human approval.")
    if not queue_total:
        blockers.append("Publishing queue is empty until one approved clear asset is queued.")
    if not strict_security_ready:
        blockers.append(security.get("next_step") or "Supabase service-role security evidence is incomplete.")
    if scheduled_queue == 0:
        blockers.append("No reviewed item has been scheduled yet.")
    elif not published_queue:
        blockers.append("Manually publish the next scheduled item at its planned time, then record the Meta post ID or manual label.")
    return {
        "percent": percent,
        "label": f"{percent}% built",
        "first_cycle_percent": first_cycle_percent,
        "first_cycle_label": f"{first_cycle_percent}% first cycle",
        "score": total_score,
        "weight": total_weight,
        "items": items,
        "blockers": blockers,
        "next_requirement": blockers[0] if blockers else "Run the final publish, metrics, and learning closeout evidence.",
        "method": "weighted_operational_readiness",
    }


async def project_completion_audit_payload():
    loop = await build_loop_status()
    workflow = build_workflow_guidance(loop)
    security = await strict_security_status_payload()
    automation = await automation_status_payload()
    completion = build_completion_status(loop, workflow, security, automation)
    launch = await launch_readiness_payload()
    meta = await meta_readiness_payload(check_graph=False)
    monthly = await monthly_carousel_acceptance_audit_payload()
    completion_watch = await latest_project_completion_watch_heartbeat()
    next_actions = []
    if completion.get("blockers"):
        next_actions.extend(completion.get("blockers") or [])
    monthly_next = monthly.get("next_step")
    if monthly_next and monthly_next not in next_actions:
        next_actions.append(monthly_next)
    launch_next = launch.get("next_step")
    if launch_next and launch_next not in next_actions:
        next_actions.append(launch_next)
    meta_next = meta.get("next_step")
    if meta_next and meta_next not in next_actions:
        next_actions.append(meta_next)
    if not next_actions:
        next_actions.append("Run one full manual publishing cycle, record metrics, and confirm learning closeout.")
    readiness = "ready_for_manual_ops"
    if completion.get("percent", 0) >= 95 and not completion.get("blockers"):
        readiness = "ready_for_live_acceptance_test"
    elif completion.get("percent", 0) < 80:
        readiness = "build_in_progress"
    payload = {
        "mode": "read_only_project_completion_audit",
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "readiness": readiness,
        "completion": completion,
        "workflow_summary": workflow.get("summary") or {},
        "security": security,
        "automation_summary": (automation or {}).get("summary") or {},
        "launch": {
            "overall_status": launch.get("overall_status"),
            "can_test_now": launch.get("can_test_now"),
            "can_use_for_manual_ops": launch.get("can_use_for_manual_ops"),
            "next_step": launch.get("next_step"),
        },
        "meta": {
            "overall_status": meta.get("overall_status"),
            "mode": meta.get("mode"),
            "next_step": meta.get("next_step"),
        },
        "monthly_acceptance": {
            "ready_count": monthly.get("ready_count"),
            "waiting_count": monthly.get("waiting_count"),
            "blocked_count": monthly.get("blocked_count"),
            "next_step": monthly.get("next_step"),
        },
        "project_completion_watch": completion_watch,
        "next_actions": next_actions[:8],
        "links": {
            "workflow_status": "/workflow/status",
            "launch_readiness": "/operations/launch-readiness",
            "launch_evidence": "/operations/launch-evidence.md",
            "monthly_acceptance_audit": "/operations/monthly-carousel-acceptance-audit.zh.md",
            "monthly_next_action_queue": "/operations/monthly-carousel-next-action-queue.zh.md",
            "meta_readiness": "/meta/readiness",
            "meta_preflight": "/meta/preflight-audit.md",
            "data_connection": "/security/data-connection",
            "project_completion_audit": "/operations/project-completion-audit.zh.md",
            "project_completion_audit_csv": "/operations/project-completion-audit.csv",
        },
        "safety": [
            "This audit is read-only and does not approve, import, queue, schedule, publish, update Notion, or call Meta.",
            "Percent is an operational readiness score, not proof that the project is fully complete.",
            "Full completion still requires real doctor/human approval evidence, scheduled/published evidence, metrics, learning closeout, and controlled Meta readiness.",
            "Meta live automation remains locked until all readiness and live-switch gates are green.",
        ],
    }
    unblock = project_unblock_board_from_audit(payload)
    payload["unblock_summary"] = {
        "ready_count": unblock.get("ready_count"),
        "blocked_count": unblock.get("blocked_count"),
        "next_action": unblock.get("next_action"),
        "next_gate": unblock.get("next_gate"),
        "next_action_source": unblock.get("next_action_source"),
        "rows": [
            {
                "gate": row.get("gate"),
                "status": row.get("status"),
                "required_action": row.get("required_action"),
                "required_evidence": row.get("required_evidence"),
                "link": row.get("link"),
            }
            for row in (unblock.get("rows") or [])[:6]
        ],
        "safety": "Read-only evidence summary; it does not approve, import, queue, schedule, publish, store secrets, or call Meta.",
    }
    return payload


async def today_project_completion_payload():
    loop = await build_loop_status()
    workflow = build_workflow_guidance(loop)
    security = await strict_security_status_payload()
    automation = await automation_status_payload()
    completion = build_completion_status(loop, workflow, security, automation)
    meta_gate = next(
        (gate for gate in (automation.get("gates") or []) if gate.get("key") == "meta"),
        {},
    )
    readiness = "ready_for_manual_ops"
    if completion.get("percent", 0) >= 95 and not completion.get("blockers"):
        readiness = "ready_for_live_acceptance_test"
    elif completion.get("percent", 0) < 80:
        readiness = "build_in_progress"
    payload = {
        "mode": "read_only_today_project_completion",
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "readiness": readiness,
        "completion": completion,
        "workflow_summary": workflow.get("summary") or {},
        "security": security,
        "automation_summary": (automation or {}).get("summary") or {},
        "launch": {
            "overall_status": "manual_ops_ready_auto_blocked"
            if security.get("supabase_rest") == "configured"
            else "setup_needed",
            "next_step": security.get("next_step") or "Continue the first manual publish and learning cycle.",
        },
        "meta": {
            "overall_status": meta_gate.get("status"),
            "next_step": "Keep Meta live switches off until readiness, scheduler, and security gates are green.",
        },
        "monthly_acceptance": {},
        "next_actions": (completion.get("blockers") or [completion.get("next_requirement")])[:8],
        "links": {
            "workflow_status": "/workflow/status",
            "project_completion_audit": "/operations/project-completion-audit.zh.md",
            "project_completion_audit_csv": "/operations/project-completion-audit.csv",
        },
        "safety": [
            "Fast homepage summary only; use the full completion audit for detailed evidence.",
            "It does not approve, import, queue, schedule, publish, store secrets, or call Meta.",
        ],
    }
    payload["unblock_summary"] = {
        key: value
        for key, value in project_unblock_board_from_audit(payload).items()
        if key in {"ready_count", "blocked_count", "next_action", "next_gate", "next_action_source"}
    }
    return payload


