def today_action_from_completion(audit: dict, unblock: dict):
    completion = audit.get("completion") or {}
    workflow_summary = audit.get("workflow_summary") or {}
    blockers = completion.get("blockers") or audit.get("next_actions") or []
    rows = unblock.get("rows") or []
    first_blocked = next((row for row in rows if row.get("status") != "ready"), {})
    text = first_blocked.get("required_action") or (blockers[0] if blockers else "у╗Ду╗ГТБђТЪЦжА╣уЏ«уіХТђЂсђѓ")
    link = first_blocked.get("link") or "/operations/project-unblock-board.zh.md"
    if "service-role" in text.lower() or "supabase" in text.lower():
        primary = {"kind": "download", "label": "СИІУййт«ЅтЁеУ»┤Тўј", "path": "/security/service-role-install-pack.md"}
    elif "FLY_API_TOKEN" in text or "Fly Deploy" in text:
        primary = {"kind": "download", "label": "СИІУййжЃеуй▓тљ»ућетїЁ", "path": "/operations/deployment-activation-pack.zh.md"}
    elif "queue" in text.lower() or "asset" in text.lower():
        primary = {"kind": "show_screen", "label": "ТЅЊт╝ђу┤аТЮљ", "screen": "assets"}
    elif "schedule" in text.lower() or "planned" in text.lower():
        primary = {"kind": "show_screen", "label": "ТЅЊт╝ђТјњуеІ", "screen": "scheduler"}
    else:
        primary = {"kind": "download", "label": "СИІУййУДБжћЂТИЁтЇЋ", "path": link}
    return {
        "source": "project_completion",
        "priority": 90,
        "eyebrow": "жА╣уЏ«СИ╗тЇАуѓ╣",
        "title": first_blocked.get("gate") or "СИІСИђТГЦ",
        "body": text,
        "status": f"{completion.get('percent', '?')}% Тђ╗СйЊ ┬и ждќУй« {completion.get('first_cycle_percent', '?')}%",
        "primary": primary,
        "secondary": [
            {"kind": "download", "label": "УДБжћЂТИЁтЇЋ", "path": "/operations/project-unblock-board.zh.md"},
            {"kind": "download", "label": "т«їТѕљт║дт«АУ«А", "path": "/operations/project-completion-audit.zh.md"},
        ],
        "next_steps": ["ТЅЊт╝ђСИ╗тіеСйю", "УАЦжйљУдЂТ▒ѓУ»ЂТЇ«", "тЏъждќжАхжЄЇТќ░ТБђТЪЦ"],
        "safety_note": "жА╣уЏ«тЇАуѓ╣ТИЁтЇЋтЈфУ»╗№╝ЏСИЇС╝џтЈЉтИЃсђЂУ«░тйЋ post IDсђЂС┐ЮтГў secret ТѕќУ░Ѓуће Metaсђѓ",
        "evidence_required": [first_blocked.get("required_evidence") or "Current workflow evidence"],
        "context": {"workflow_summary": workflow_summary},
    }


async def safe_today_payload(name: str, payload_coro, timeout_seconds: int = 12):
    try:
        return await asyncio.wait_for(payload_coro, timeout=timeout_seconds)
    except asyncio.TimeoutError:
        return {
            "_today_unavailable": name,
            "_today_error": "timeout",
            "_today_timeout_seconds": timeout_seconds,
        }
    except Exception as exc:
        return {
            "_today_unavailable": name,
            "_today_error": type(exc).__name__,
        }


def payload_unavailable_summary(payload: dict):
    if not payload.get("_today_unavailable"):
        return None
    return {
        "section": payload.get("_today_unavailable"),
        "error": payload.get("_today_error"),
        "timeout_seconds": payload.get("_today_timeout_seconds"),
    }


async def today_next_action_payload():
    audit, monthly, cycle, closeout = await asyncio.gather(
        safe_today_payload("project_completion", today_project_completion_payload(), timeout_seconds=6),
        safe_today_payload("monthly_carousel", monthly_carousel_next_action_queue_payload()),
        safe_today_payload("cycle_command_center", today_cycle_command_payload(), timeout_seconds=3),
        safe_today_payload("publishing_closeout", publishing_closeout_payload()),
    )
    unblock = project_unblock_board_from_audit(audit)
    candidates = [
        today_action_from_monthly(monthly),
        today_action_from_closeout(closeout),
        today_action_from_cycle(cycle),
        today_action_from_completion(audit, unblock),
    ]
    candidates = [item for item in candidates if item]
    candidates.sort(key=lambda item: int(item.get("priority") or 999))
    action = candidates[0] if candidates else today_action_from_completion(audit, unblock)
    for group in (action.get("secondary") or []):
        if group.get("path"):
            group["filename"] = today_action_download_filename(group.get("path"))
    primary = action.get("primary") or {}
    if primary.get("path"):
        primary["filename"] = today_action_download_filename(primary.get("path"))
    return {
        "mode": "read_only_today_next_action",
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "action": action,
        "candidates": candidates[:5],
        "project_completion": {
            "percent": (audit.get("completion") or {}).get("percent"),
            "first_cycle_percent": (audit.get("completion") or {}).get("first_cycle_percent"),
            "readiness": audit.get("readiness"),
        },
        "monthly": {
            "asset_count": monthly.get("asset_count"),
            "gate_counts": monthly.get("gate_counts") or {},
            "stage_counts": monthly.get("stage_counts") or {},
            "top_three": monthly.get("top_three") or [],
        },
        "publishing_closeout": {
            "overall_status": closeout.get("overall_status"),
            "counts": closeout.get("counts") or {},
            "next_action": closeout.get("next_action") or {},
        },
        "unblock": {
            "ready_count": unblock.get("ready_count"),
            "blocked_count": unblock.get("blocked_count"),
            "next_action": unblock.get("next_action"),
        },
        "availability": {
            "partial": any(
                payload.get("_today_unavailable")
                for payload in (audit, monthly, cycle, closeout)
            ),
            "unavailable": [
                item
                for item in [
                    payload_unavailable_summary(audit),
                    payload_unavailable_summary(monthly),
                    payload_unavailable_summary(cycle),
                    payload_unavailable_summary(closeout),
                ]
                if item
            ],
        },
        "links": {
            "today_next_action": "/operations/today-next-action",
            "today_next_action_zh": "/operations/today-next-action.zh.md",
            "project_unblock": "/operations/project-unblock-board.zh.md",
            "monthly_next_action_queue": "/operations/monthly-carousel-next-action-queue.zh.md",
            "publishing_closeout": "/operations/publishing-closeout.zh.md",
            "cycle_command_center": "/operations/cycle-command-center.md",
        },
        "safety": [
            "This endpoint is read-only.",
            "It does not approve, import, queue, schedule, publish, record post IDs, store secrets, update Notion, or call Meta.",
            "The UI should show one main action first and keep advanced tools behind More.",
        ],
    }


@app.get("/operations/today-next-action")
async def operations_today_next_action(_: None = Depends(require_access_token)):
    return await today_next_action_payload()


